-- Poems batch 449
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-27','巴女謠','于鵠','唐','御定全唐诗','yuding','','[]','巴女騎牛唱竹枝，藕絲菱葉傍江時。',32,'御定全唐詩/json/310.json','["巴女騎牛唱竹枝，藕絲菱葉傍江時。", "不愁日暮還家錯，記得芭蕉出槿籬。"]'),
('yuding-28','公子行','于鵠','唐','御定全唐诗','yuding','','[]','少年初拜大長秋，半醉垂鞭見列侯。馬上抱雞三市鬥，',40,'御定全唐詩/json/310.json','["少年初拜大長秋，半醉垂鞭見列侯。馬上抱雞三市鬥，", "更向院西新買宅，月波春水入門流。"]'),
('yuding-29','長安游','於鵠','唐','御定全唐诗','yuding','','[]','久臥長安春複秋，五侯長樂客長愁。繡簾朱轂逢花住，',40,'御定全唐詩/json/310.json','["久臥長安春複秋，五侯長樂客長愁。繡簾朱轂逢花住，", "年年只是看他貴，不及南山任白頭。"]'),
('yuding-30','別齊太守','于鵠','唐','御定全唐诗','yuding','','[]','花裏南樓春夜寒，還如王屋上天壇。',32,'御定全唐詩/json/310.json','["花裏南樓春夜寒，還如王屋上天壇。", "歸山不道無明月，誰共相從到曉看。"]'),
('yuding-31','登古城','於鵠','唐','御定全唐诗','yuding','','[]','獨上閑城卻下遲，秋山慘慘塚累累。',32,'御定全唐詩/json/310.json','["獨上閑城卻下遲，秋山慘慘塚累累。", "當時還有登城者，荒草如今知是誰。"]'),
('yuding-32','哭劉夫子','于鵠','唐','御定全唐诗','yuding','','[]','近問南州客，雲亡已數春。痛心曾受業，追服恨無親。',48,'御定全唐詩/json/310.json','["近問南州客，雲亡已數春。痛心曾受業，追服恨無親。", "孀婦歸鄉里，書齋屬四鄰。不知經亂後，奠祭有何人。"]'),
('yuding-33','醉後寄山中友人','于鵠','唐','御定全唐诗','yuding','','[]','昨日山家春酒濃，野人相勸久從容。獨憶卸冠眠細草，',40,'御定全唐詩/json/310.json','["昨日山家春酒濃，野人相勸久從容。獨憶卸冠眠細草，", "知己尚嫌身酩酊，路人應恐笑龍鍾。"]'),
('yuding-34','溫泉僧房','於鵠','唐','御定全唐诗','yuding','','[]','雲裏前朝寺，修行獨幾年。山村無施食，盥漱亦安禪。',48,'御定全唐詩/json/310.json','["雲裏前朝寺，修行獨幾年。山村無施食，盥漱亦安禪。", "古塔巢溪鳥，深房閉穀泉。自言曾入室，知處梵王天。"]'),
('yuding-35','題美人','于鵠','唐','御定全唐诗','yuding','','[]','秦女窺人不解羞，攀花趁蝶出牆頭。',32,'御定全唐詩/json/310.json','["秦女窺人不解羞，攀花趁蝶出牆頭。", "胸前空帶宜男草，嫁得蕭郎愛遠遊。"]'),
('yuding-36','尋李暹','於鵠','唐','御定全唐诗','yuding','','[]','任性常多出，人來得見稀。市樓逢酒住，野寺送僧歸。',48,'御定全唐詩/json/310.json','["任性常多出，人來得見稀。市樓逢酒住，野寺送僧歸。", "簷下懸秋葉，籬頭曬褐衣。門前南北路，誰肯入柴扉。"]'),
('yuding-37','尋李逸人舊居','於鵠','唐','御定全唐诗','yuding','','[]','舊隱松林下，沖泉入兩涯。琴書隨弟子，雞犬在鄰家。',48,'御定全唐詩/json/310.json','["舊隱松林下，沖泉入兩涯。琴書隨弟子，雞犬在鄰家。", "茅屋長黃菌，槿籬生白花。幽墳無處訪，恐是入煙霞。"]'),
('yuding-38','贈碧玉','於鵠','唐','御定全唐诗','yuding','','[]','新繡籠裙豆蔻花，路人笑上返金車。',32,'御定全唐詩/json/310.json','["新繡籠裙豆蔻花，路人笑上返金車。", "霓裳禁曲無人解，暗問梨園弟子家。"]'),
('yuding-39','舟中月明夜聞笛','於鵠','唐','御定全唐诗','yuding','','[]','浦裏移舟候信風，蘆花漠漠夜江空。',32,'御定全唐詩/json/310.json','["浦裏移舟候信風，蘆花漠漠夜江空。", "更深何處人吹笛，疑是孤吟寒水中。"]'),
('yuding-40','送遷客二首','於鵠','唐','御定全唐诗','yuding','','[]','得罪誰人送，來時不到家。白頭無侍子，多病向天涯。',96,'御定全唐詩/json/310.json','["得罪誰人送，來時不到家。白頭無侍子，多病向天涯。", "莽蒼淩江水，黃昏見塞花。如今賈誼賦，不漫說長沙。", "流人何處去，萬里向江州。孤驛瘴煙重，行人巴草秋。", "上帆南去遠，送雁北看愁。遍問炎方客，無人得白頭。"]'),
('yuding-41','贈王道者','於鵠','唐','御定全唐诗','yuding','','[]','去尋長不出，門似絕人行。床下石苔滿，屋頭秋草生。',48,'御定全唐詩/json/310.json','["去尋長不出，門似絕人行。床下石苔滿，屋頭秋草生。", "學琴寒月短，寫易晚窗明。唯到黃昏後，溪中聞磬聲。"]'),
('yuding-42','題合溪幹洞','於鵠','唐','御定全唐诗','yuding','','[]','渡水傍山尋絕壁，白雲飛處洞天開。',32,'御定全唐詩/json/310.json','["渡水傍山尋絕壁，白雲飛處洞天開。", "仙人來往行無跡，石徑春風長綠苔。"]'),
('yuding-43','過張老園林','於鵠','唐','御定全唐诗','yuding','','[]','身老無修飾，頭巾用白紗。開門朝掃徑，輦水夜澆花。',48,'御定全唐詩/json/310.json','["身老無修飾，頭巾用白紗。開門朝掃徑，輦水夜澆花。", "藥氣聞深巷，桐陰到數家。不愁還酒債，腰下有丹砂。"]'),
('yuding-44','寓意','於鵠','唐','御定全唐诗','yuding','','[]','自小看花長不足，江邊尋得數株紅。',32,'御定全唐詩/json/310.json','["自小看花長不足，江邊尋得數株紅。", "黃昏人散東風起，吹落誰家明月中。"]'),
('yuding-45','哭王都護','于鵠','唐','御定全唐诗','yuding','','[]','老將明王識，臨終拜上公。告哀鄉路遠，助葬戍城空。',48,'御定全唐詩/json/310.json','["老將明王識，臨終拜上公。告哀鄉路遠，助葬戍城空。", "素幔朱門裏，銘旌秋巷中。史官如不濫，獨傳說英雄。"]'),
('yuding-46','餞司農宋卿立太尉碑了還江東','於鵠','唐','御定全唐诗','yuding','','[]','追立新碑日，憐君苦一身。遠移深澗石，助立故鄉人。',48,'御定全唐詩/json/310.json','["追立新碑日，憐君苦一身。遠移深澗石，助立故鄉人。", "草色荒墳綠，松陰古殿春。平生心已遂，歸去得垂綸。"]'),
('yuding-47','送唐大夫讓節歸山','於鵠','唐','御定全唐诗','yuding','','[]','年老功成乞罷兵，玉階匍匐進雙旌。朱門鴛瓦為仙觀，',40,'御定全唐詩/json/310.json','["年老功成乞罷兵，玉階匍匐進雙旌。朱門鴛瓦為仙觀，", "到時浸發春泉裏，猶夢紅樓簫管聲。"]'),
('yuding-48','買山吟','於鵠','唐','御定全唐诗','yuding','','[]','買得幽山屬漢陽，槿籬疏處種桄榔。',32,'御定全唐詩/json/310.json','["買得幽山屬漢陽，槿籬疏處種桄榔。", "唯有獼猴來往熟，弄人拋果滿書堂。"]'),
('yuding-49','古詞三首','於鵠','唐','御定全唐诗','yuding','','[]','素絲帶金地，窗間掬飛塵。偷得鳳凰釵，門前乞行人。',72,'御定全唐詩/json/310.json','["素絲帶金地，窗間掬飛塵。偷得鳳凰釵，門前乞行人。", "新長青絲發，啞啞言語黠。隨人敲銅鏡，街頭救明月。", "東家新長兒，與妾同時生。並長兩心熟，到大相呼名。"]'),
('yuding-50','秦越人洞中詠','於鵠','唐','御定全唐诗','yuding','','[]','扁鵲得仙處，傳是西南峰。年年山下人，長見騎白龍。',120,'御定全唐詩/json/310.json','["扁鵲得仙處，傳是西南峰。年年山下人，長見騎白龍。", "洞門黑無底，日夜唯雷風。清齋將入時，戴星兼抱松。", "石徑陰且寒，地響知遠鐘。似行山林外，聞葉履聲重。", "低礙更俯身，漸遠晝夜同。時時白蝙蝠，飛入茅衣中。", "行久路轉窄，靜聞水淙淙。但願逢一人，自得朝天宮。"]'),
('yuding-51','宿西山修下元齋詠','於鵠','唐','御定全唐诗','yuding','','[]','幽人在何處，松檜深冥冥。西峰望紫雲，知處安期生。',144,'御定全唐詩/json/310.json','["幽人在何處，松檜深冥冥。西峰望紫雲，知處安期生。", "沐浴溪水曖，新衣禮仙名。脫屐入靜堂，繞像隨禮行。", "碧紗籠寒燈，長幡綴金鈴。林下聽法人，起坐枯葉聲。", "啟奏修律儀，天曙山鳥鳴。分行布菅茅，列坐滿中庭。", "持齋候撞鐘，玉函散寶經。焚香開卷時，照耀金室明。", "投簡石洞深，稱過上帝靈。學道能苦心，自古無不成。"]'),
('yuding-52','過淩霄洞天謁張先生祠','于鵠','唐','御定全唐诗','yuding','','[]','戢戢亂峰裏，一峰獨淩天。下看如尖高，上有十裏泉。',180,'御定全唐詩/json/310.json','["戢戢亂峰裏，一峰獨淩天。下看如尖高，上有十裏泉。", "志人愛幽深，一住五十年。懸牘到其上，乘牛耕藥田。", "衣食不下求，乃是雲中仙。山僧獨知處，相引沖碧煙。", "斷崖晝昏黑，槎臬橫只椽。面壁攀石棱，養力方敢前。", "累歇日已沒，始到茅堂邊。見客不問誰，禮質無周旋。", "醉臥枕欹樹，寒坐展青氈。折松掃藜床，秋果顏色鮮。", "煉蜜敲石炭，洗澡乘瀑泉。白犬舐客衣，驚走聞腥膻。", "乃知軒冕徒，寧比雲壑眠。"]'),
('yuding-53','早上淩霄第六峰入紫溪禮白鶴觀祠','于鵠','唐','御定全唐诗','yuding','','[]','路轉第六峰，傳是十里程。放石試淺深，eg壁蛇鳥驚。',157,'御定全唐詩/json/310.json','["路轉第六峰，傳是十里程。放石試淺深，eg壁蛇鳥驚。", "欲下先襞衣，路底避枯莖。回途歇嵌窟，整帶重冠纓。", "及到紫石溪，晻晻已天明。漸近神仙居，桂花濕溟溟。", "陰苔無人蹤，時得白鶴翎。忽然見朱樓，象牌題玉京。", "沉沉五雲影，香風散縈縈。清齋上玉堂，窗戶懸水精。", "青童撞金屑，杵臼聲丁丁。膻腥遙問誰，稽首稱姓名。", "若容在溪口，願乞殘雪英。"]'),
('yuding-54','山中訪道者','於鵠','唐','御定全唐诗','yuding','','[]','觸煙入溪口，岸岸唯檉櫟。其中盡碧流，十裏不通屐。',157,'御定全唐詩/json/310.json','["觸煙入溪口，岸岸唯檉櫟。其中盡碧流，十裏不通屐。", "出林山始轉，絕徑緣峭壁。把藤借行勢，側足憑石脈。", "gS牙斷行處，光滑猿猱跡。忽然風景異，乃到神仙宅。", "天晴茅屋頭，殘雲蒸氣白。隔窗梳發聲，久立聞吹笛。", "抱琴出門來，不顧人間客。山院不灑掃，四時自虛寂。", "落葉埋長松，出地才數尺。曾讀上清經，知注長生籍。", "願示不死方，何山有瓊液。"]'),
('yuding-55','寄盧儼員外秋衣詞','於鵠','唐','御定全唐诗','yuding','','[]','寄遠空以心，心誠亦難知。篋中有秋帛，裁作遠客衣。',120,'御定全唐詩/json/310.json','["寄遠空以心，心誠亦難知。篋中有秋帛，裁作遠客衣。", "縫製雖女功，盡度手自持。容貌常目中，長短不復疑。", "斜縫密且堅，遊客多塵緇。意欲都無言，浣濯耐歲時。", "殷勤托行人，傳語慎勿遺。別來年已老，亦聞鬢成絲。", "縱然更相逢，握手唯是悲。所寄莫複棄，願見長相思。"]'),
('yuding-56','種樹','於鵠','唐','御定全唐诗','yuding','','[]','一樹新栽益四鄰，野夫如到舊山春。',32,'御定全唐詩/json/310.json','["一樹新栽益四鄰，野夫如到舊山春。", "樹成多是人先老，垂白看他攀折人。"]'),
('yuding-57','哭李暹','於鵠','唐','御定全唐诗','yuding','','[]','驅馬街中哭送君，靈車碾雪隔城聞。',32,'御定全唐詩/json/310.json','["驅馬街中哭送君，靈車碾雪隔城聞。", "唯有山僧與樵客，共舁孤櫬入幽墳。"]'),
('yuding-58','古挽歌','於鵠','唐','御定全唐诗','yuding','','[]','雙轍出郭門，綿綿東西道。送死多於生，幾人得終老。',144,'御定全唐詩/json/310.json','["雙轍出郭門，綿綿東西道。送死多於生，幾人得終老。", "見此切肺肝，不如歸山好。不聞哀哭聲，默默安懷抱。", "時盡從物化，又免生憂撓。世間壽者稀，盡為悲傷惱。", "送哭誰家車，靈幡紫帶長。青童抱何物，明月與香囊。", "可惜羅衣色，看舁入水泉。莫愁埏道暗，燒漆得千年。", "陰風吹黃蒿，挽歌度秋水。車馬卻歸城，孤墳月明裏。"]'),
('yuding-59','悼孩子','于鵠','唐','御定全唐诗','yuding','','[]','年長始一男，心亦頗自娛。生來歲未周，奄然卻歸無。',96,'御定全唐詩/json/310.json','["年長始一男，心亦頗自娛。生來歲未周，奄然卻歸無。", "裸送不以衣，瘞埋於中衢。乳母抱出門，所生亦隨呼。", "嬰孩無哭儀，禮經不可逾。親戚相問時，抑悲空歎籲。", "繈褓在舊床，每見立踟躕。靜思益傷情，畏老為獨夫。"]'),
('yuding-60','別舊山','於鵠','唐','御定全唐诗','yuding','','[]','舊伴同遊盡卻回，雲中獨宿守花開。',32,'御定全唐詩/json/310.json','["舊伴同遊盡卻回，雲中獨宿守花開。", "自是去人身漸老，暮山流水任東來。"]'),
('yuding-61','寄周惲','於鵠','唐','御定全唐诗','yuding','','[]','家在荒陂長似秋，蓼花芹葉水蟲幽。',32,'御定全唐詩/json/310.json','["家在荒陂長似秋，蓼花芹葉水蟲幽。", "去年相伴尋山客，明月今宵何處遊。"]'),
('yuding-62','野田行','於鵠','唐','御定全唐诗','yuding','','[]','日暮出古城，野田何茫茫。寒狐上孤塚，鬼火燒白楊。',40,'御定全唐詩/json/310.json','["日暮出古城，野田何茫茫。寒狐上孤塚，鬼火燒白楊。", "昔人未為泉下客，若到此中還斷腸。"]'),
('yuding-63','塞上曲','于鵠','唐','御定全唐诗','yuding','','[]','行人朝走馬，直走薊城傍。薊城通漢北，萬里別吳鄉。',72,'御定全唐詩/json/310.json','["行人朝走馬，直走薊城傍。薊城通漢北，萬里別吳鄉。", "海上一烽火，沙中百戰場。軍書發上郡，春色度河陽。", "嫋嫋漢宮柳，青青胡地桑。琵琶出塞曲，橫笛斷君腸。"]'),
('yuding-64','襄陽寒食','於鵠','唐','御定全唐诗','yuding','','[]','煙水初銷見萬家，東風吹柳萬條斜。',32,'御定全唐詩/json/310.json','["煙水初銷見萬家，東風吹柳萬條斜。", "大堤欲上誰相伴，馬踏春泥半是花。"]'),
('yuding-65','泛舟入後溪','於鵠','唐','御定全唐诗','yuding','','[]','雨餘芳草淨沙塵，水綠沙平一帶春。',32,'御定全唐詩/json/310.json','["雨餘芳草淨沙塵，水綠沙平一帶春。", "唯有啼鵑似留客，桃花深處更無人。"]'),
('yuding-0','寶劍篇','劉長川','唐','御定全唐诗','yuding','','[]','寶劍不可得，相逢幾許難。今朝一度見，赤色照人寒。',48,'御定全唐詩/json/311.json','["寶劍不可得，相逢幾許難。今朝一度見，赤色照人寒。", "匣裏星文動，環邊月影殘。自然神鬼伏，無事莫空彈。"]'),
('yuding-1','將赴東都上李相公','劉長川','唐','御定全唐诗','yuding','','[]','四海兵初偃，平津閣正開。誰知大爐下，還有不然灰。',24,'御定全唐詩/json/311.json','["四海兵初偃，平津閣正開。誰知大爐下，還有不然灰。"]'),
('yuding-2','寄邢逸人','鄭常','唐','御定全唐诗','yuding','','[]','羨君無外事，日與世情違。地僻人難到，溪深鳥自飛。',48,'御定全唐詩/json/311.json','["羨君無外事，日與世情違。地僻人難到，溪深鳥自飛。", "儒衣荷葉老，野飯藥苗肥。疇昔江湖意，而今憶共歸。"]'),
('yuding-3','送頭陀上人赴廬山寺','鄭常','唐','御定全唐诗','yuding','','[]','僧家無住著，早晚出東林。得道非真相，頭陀是苦心。',48,'御定全唐詩/json/311.json','["僧家無住著，早晚出東林。得道非真相，頭陀是苦心。", "持齋山果熟，倚錫野雲深。溪寺誰相待，香花與梵音。"]'),
('yuding-4','謫居漢陽白沙口阻雨，因題驛亭','鄭常','唐','御定全唐诗','yuding','','[]','漢陽無遠近，見說過湓城。雲雨經春客，江山幾日程。',48,'御定全唐詩/json/311.json','["漢陽無遠近，見說過湓城。雲雨經春客，江山幾日程。", "終隨鷗鳥去，只待海潮生。前路逢漁父，多慚問姓名。"]'),
('yuding-5','穆陵路','陳存','唐','御定全唐诗','yuding','','[]','西遊匣長劍，日暮湘楚間。歇馬上秋草，逢人問故關。',48,'御定全唐詩/json/311.json','["西遊匣長劍，日暮湘楚間。歇馬上秋草，逢人問故關。", "孤村綠塘水，曠野白雲山。方念此中去，何時此路還。"]'),
('yuding-6','清溪館作','陳存','唐','御定全唐诗','yuding','','[]','指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。',48,'御定全唐詩/json/311.json','["指途清溪裏，左右唯深林。雲蔽望鄉處，雨愁為客心。", "遇人多物役，聽鳥時幽音。何必滄浪水，庶茲浣塵襟。"]'),
('yuding-7','寓居武丁館','陳存','唐','御定全唐诗','yuding','','[]','暑雨飄已過，涼飆觸幽衿。虛館無喧塵，綠槐多晝陰。',48,'御定全唐詩/json/311.json','["暑雨飄已過，涼飆觸幽衿。虛館無喧塵，綠槐多晝陰。", "俯視古苔積，仰聆早蟬吟。放卷一長想，閉門千里心。"]'),
('yuding-8','楚州贈別周願侍禦','陳存','唐','御定全唐诗','yuding','','[]','漂泊楚水來，舍舟坐高館。途窮在中路，孤征慕前伴。',48,'御定全唐詩/json/311.json','["漂泊楚水來，舍舟坐高館。途窮在中路，孤征慕前伴。", "風雨一留宿，關山去欲懶。淮南木葉飛，夜聞廣陵散。"]'),
('yuding-9','送劉秀才南歸','陳存','唐','御定全唐诗','yuding','','[]','鳥啼楊柳垂，此別千萬里。古路入商山，春風去灞水。',48,'御定全唐詩/json/311.json','["鳥啼楊柳垂，此別千萬里。古路入商山，春風去灞水。", "停車落日在，罷酒離人起。蓬戶寄龍沙，送歸情詎已。"]'),
('yuding-10','丹陽作','陳存','唐','御定全唐诗','yuding','','[]','暫入新豐市，猶聞舊酒香。抱琴沽一醉，盡日臥垂楊。',24,'御定全唐詩/json/311.json','["暫入新豐市，猶聞舊酒香。抱琴沽一醉，盡日臥垂楊。"]'),
('yuding-11','早行','王觀','唐','御定全唐诗','yuding','','[]','雞唱催人起，又生前去愁。路明殘月在，山露宿雲收。',48,'御定全唐詩/json/311.json','["雞唱催人起，又生前去愁。路明殘月在，山露宿雲收。", "村店煙火動，漁家燈燭幽。趨名與趨利，行役幾時休。"]'),
('yuding-12','贈營妓','崔瓘','唐','御定全唐诗','yuding','','[]','寒簷寂寂雨霏霏，候館蕭條燭燼微。',32,'御定全唐詩/json/311.json','["寒簷寂寂雨霏霏，候館蕭條燭燼微。", "只有今宵同此宴，翠娥佯醉欲先歸。"]'),
('yuding-13','酒席賦得匏瓢','鄭審','唐','御定全唐诗','yuding','','[]','華閣與賢開，仙瓢自遠來。幽林嘗伴許，陋巷亦隨回。',48,'御定全唐詩/json/311.json','["華閣與賢開，仙瓢自遠來。幽林嘗伴許，陋巷亦隨回。", "掛影憐紅壁，傾心向綠杯。何曾斟酌處，不使玉山頹。"]'),
('yuding-14','奉使巡檢兩京路種果樹事畢入秦因詠','鄭審','唐','御定全唐诗','yuding','','[]','聖德周天壤，韶華滿帝畿。九重承渙汗，千里樹芳菲。',96,'御定全唐詩/json/311.json','["聖德周天壤，韶華滿帝畿。九重承渙汗，千里樹芳菲。", "陝塞餘陰薄，關河舊色微。發生和氣動，封植眾心歸。", "春露條應弱，秋霜果定肥。影移行子蓋，香撲使臣衣。", "入徑迷馳道，分行接禁闈。何當扈仙蹕，攀折奉恩輝。"]'),
('yuding-15','丹陽作','朱彬','唐','御定全唐诗','yuding','','[]','暫入新豐市，猶聞舊酒香。抱琴沽一醉，盡日臥垂楊。',24,'御定全唐詩/json/311.json','["暫入新豐市，猶聞舊酒香。抱琴沽一醉，盡日臥垂楊。"]'),
('yuding-16','采桑','李彥遠','唐','御定全唐诗','yuding','','[]','采桑畏日高，不待春眠足。攀條有餘態，那矜貌如玉。',48,'御定全唐詩/json/311.json','["采桑畏日高，不待春眠足。攀條有餘態，那矜貌如玉。", "千金豈不贈，五馬空躑躅。何以變真性，幽篁雪中綠。"]'),
('yuding-17','章仇公席上詠真珠姬','范元凱','唐','御定全唐诗','yuding','','[]','神女初離碧玉階，彤雲猶擁牡丹鞋。',32,'御定全唐詩/json/311.json','["神女初離碧玉階，彤雲猶擁牡丹鞋。", "應知子建憐羅襪，顧步裴回拾翠釵。"]'),
('yuding-0','爛柯山四首：最高頂','劉迥','唐','御定全唐诗','yuding','','[]','白雲引策杖，苔徑誰往還。漸見松樹偃，時聞鳥聲閑。',36,'御定全唐詩/json/312.json','["白雲引策杖，苔徑誰往還。漸見松樹偃，時聞鳥聲閑。", "豁然喧氛盡，獨對萬重山。"]'),
('yuding-1','爛柯山四首：石橋','劉迥','唐','御定全唐诗','yuding','','[]','石橋架絕壑，蒼翠橫鳥道。憑檻雲腳下，頹陽日猶蚤。',36,'御定全唐詩/json/312.json','["石橋架絕壑，蒼翠橫鳥道。憑檻雲腳下，頹陽日猶蚤。", "霓裳倘一遇，千載長不老。"]'),
('yuding-2','爛柯山四首：仙人棋','劉迥','唐','御定全唐诗','yuding','','[]','靈境偶一尋，洞天碧雲上。爛柯有遺跡，羽客何由訪。',36,'御定全唐詩/json/312.json','["靈境偶一尋，洞天碧雲上。爛柯有遺跡，羽客何由訪。", "日暮悵欲還，晴煙滿千嶂。"]'),
('yuding-3','爛柯山四首：石室二禪師','劉迥','唐','御定全唐诗','yuding','','[]','繩床宴坐久，石窟絕行跡。能在人代中，遂將人代隔。',36,'御定全唐詩/json/312.json','["繩床宴坐久，石窟絕行跡。能在人代中，遂將人代隔。", "白雲風颺飛，非欲待歸客。"]'),
('yuding-4','前年春與獨孤常州兄花時為別倏已三年矣今鶯花又爾睹物增懹因之抒情聊以奉寄','李幼卿','唐','御定全唐诗','yuding','','[]','近日霜毛一番新，別時芳草兩回春。不堪花落花開處，',40,'御定全唐詩/json/312.json','["近日霜毛一番新，別時芳草兩回春。不堪花落花開處，", "緣君愛我疵瑕少，願竊仁風寄老身。"]'),
('yuding-5','游爛柯山四首','李幼卿','唐','御定全唐诗','yuding','','[]','拂霧理孤策，薄霄眺層岑。迥升煙霧外，豁見天地心。',144,'御定全唐詩/json/312.json','["拂霧理孤策，薄霄眺層岑。迥升煙霧外，豁見天地心。", "物象不可及，遲回空詠吟。", "巨石何崔嵬，橫橋架山頂。傍通日月過，仰望虹霓迥。", "聖者開津梁，誰能度茲嶺。", "二仙自圍棋，偶與樵夫會。仙家異人代，俄頃千年外。", "笙鶴何時還，儀形尚相對。", "石室過雲外，二僧儼禪寂。不語對空山，無心向來客。", "作禮未及終，忘循舊形跡。"]'),
('yuding-6','游爛柯山四首','李深','唐','御定全唐诗','yuding','','[]','尋源路不迷，絕頂與雲齊。坐引群峰小，平看萬木低。',144,'御定全唐詩/json/312.json','["尋源路不迷，絕頂與雲齊。坐引群峰小，平看萬木低。", "雙林春色上，正有子規啼。", "嵌空橫洞天，磅礴倚崖巘。宛如虹勢出，可賞不可轉。", "真興得津梁，抽簪永遊衍。", "羽客無姓名，仙棋但聞見。行看負薪客，坐使桑田變。", "懷古正怡然，前山早鶯囀。", "稽首期發蒙，吾師豈無說。安禪即方丈，演法皆寂滅。", "鳴磬雨花香，齋堂飯松屑。"]'),
('yuding-7','游爛柯山','羊滔','唐','御定全唐诗','yuding','','[]','步登春岩裏，更上最遠山。聊見宇宙闊，遂令身世閑。',144,'御定全唐詩/json/312.json','["步登春岩裏，更上最遠山。聊見宇宙闊，遂令身世閑。", "清輝賞不盡，高駕何時還。", "石樑聳千盡，高盼出林□。亙壑躡丹虹，排雲弄清影。", "路期訪道客，游衍空井井。", "采薪窮冥搜，深路轉清映。安知洞天裏，偶坐得棋聖。", "至今追靈跡，可用陶靜性。", "沙門何處人，攜手俱滅跡。深入不動境，乃知真圓寂。", "有時歸羅浮，白日見飛錫。"]'),
('yuding-8','游爛柯山','薛戎','唐','御定全唐诗','yuding','','[]','登岩已寂曆，絕頂更岧嶢。響像如天近，窺臨與世遙。',144,'御定全唐詩/json/312.json','["登岩已寂曆，絕頂更岧嶢。響像如天近，窺臨與世遙。", "悠然暢心目，萬慮一時銷。", "聖遊本無跡，留此示津梁。架險知何適，遺名但不亡。", "只今成佛宇，化度果難量。", "二仙行自適，日月徒遷徙。不語寄手談，無心引樵子。", "蒙分一丸藥，相偶窮年祀。", "仙山習禪處，了知通李釋。昔作異時人，今成相對寂。", "便是不二門，自生瞻仰意。"]'),
('yuding-9','游爛柯山','謝勮','唐','御定全唐诗','yuding','','[]','獨淩清景出，下視眾山中。雲日遙相對，川原無不通。',144,'御定全唐詩/json/312.json','["獨淩清景出，下視眾山中。雲日遙相對，川原無不通。", "自致高標末，何心待馭風。", "宛演橫半規，穹崇翠微上。雲扃掩苔石，千古無人賞。", "寧知後賢心，登此共來往。", "仙弈示樵夫，能言忘歸路。因看斧柯爛，孫子發已素。", "孰雲遺跡久，舉意如旦暮。", "仙僧會真要，應物常淵默。惟將無住理，轉與信人說。", "月影清江中，可觀不可得。"]'),
('yuding-0','奉和聖制三日書懷因以示百寮','崔元翰','唐','御定全唐诗','yuding','','[]','佳節上元巳，芳時屬暮春。流觴想蘭亭，捧劍傳金人。',72,'御定全唐詩/json/313.json','["佳節上元巳，芳時屬暮春。流觴想蘭亭，捧劍傳金人。", "風輕水初綠，日遲花更新。天文信昭回，皇道頗敷陳。", "恭己每從儉，清心常保真。戒茲游衍樂，書以示群臣。"]'),
('yuding-1','奉和聖制重陽旦日百寮曲江宴示懷','崔元翰','唐','御定全唐诗','yuding','','[]','偶聖睹昌期，受恩慚弱質。幸逢良宴會，況是清秋日。',120,'御定全唐詩/json/313.json','["偶聖睹昌期，受恩慚弱質。幸逢良宴會，況是清秋日。", "遠岫對壺觴，澄瀾映簪紱。炮羔備豐膳，集鳳調鳴律。", "薄劣廁英豪，歡娛忘衰疾。平皋行雁下，曲渚雙鳧出。", "沙岸菊開花，霜枝果垂實。天文見成象，帝念資勤恤。", "探道得玄珠，齋心居特室。豈如橫汾唱，其事徒驕逸。"]'),
('yuding-2','奉和聖制中元日題奉敬寺','崔元翰','唐','御定全唐诗','yuding','','[]','妙道非本說，殊途成異名。聖人得其要，俱以化群生。',108,'御定全唐詩/json/313.json','["妙道非本說，殊途成異名。聖人得其要，俱以化群生。", "鳳吹從上苑，龍宮連外城。花鬘列後殿，雲車駐前庭。", "松竹含新秋，軒窗有餘清。緬懷崆峒事，須繼簫管聲。", "離相境都寂，忘言理更精。域中信稱大，天下乃為輕。", "屈己由濟物，堯心豈所榮。"]'),
('yuding-3','奉和登玄武樓觀射即事書懷賜孟涉應制','崔元翰','唐','御定全唐诗','yuding','','[]','甯歲常有備，殊方靡不賓。禁營列武衛，帝座彰威神。',96,'御定全唐詩/json/313.json','["甯歲常有備，殊方靡不賓。禁營列武衛，帝座彰威神。", "講事一臨幸，加恩遍撫巡。城高鳳樓聳，場迥獸侯新。", "飲羽連百中，控弦逾六鈞。揀材盡爪士，受任皆信臣。", "光賞文藻麗，便繁心膂親。複如觀太清，昭爛垂芳辰。"]'),
('yuding-4','清明節郭侍御偶與李侍御孔校書王秀才遊開化寺臥病不得同遊賦得十韻兼呈馬十八郎丞公','崔元翰','唐','御定全唐诗','yuding','','[]','山色入層城，鐘聲臨複岫。乘閑息邊事，探異憐春候。',120,'御定全唐詩/json/313.json','["山色入層城，鐘聲臨複岫。乘閑息邊事，探異憐春候。", "曲閣下重階，回廊遙對溜。石間花遍落，草上雲時覆。", "鑽火見樵人，飲泉逢野獸。道情親法侶，時望登朝右。", "執憲糾奸邪，刊書正訛謬。茂才當時選，公子生人秀。", "贈答繼篇章，歡娛重朋舊。垂簾獨衰疾，擊缶酬金奏。"]'),
('yuding-5','雜言奉和聖制至承光院見自生藤感其得地因以成詠應制','崔元翰','唐','御定全唐诗','yuding','','[]','新藤正可玩，得地又蓬時。羅生密葉交綠蔓，',88,'御定全唐詩/json/313.json','["新藤正可玩，得地又蓬時。羅生密葉交綠蔓，", "遙依千華殿，稍上萬年枝。餘芳連桂樹，積潤傍蓮池。", "豈如幽谷無人見，空覆荒榛雜兔絲。聖心對此應有感，", "聘丘園，訪茅茨，為謝中林士，王道本無私。"]'),
('yuding-6','雨中對後簷叢竹','崔元翰','唐','御定全唐诗','yuding','','[]','含風搖硯水，帶雨拂牆衣。乍似秋江上，漁家半掩扉。',24,'御定全唐詩/json/313.json','["含風搖硯水，帶雨拂牆衣。乍似秋江上，漁家半掩扉。"]'),
('yuding-7','賦得沈珠於泉','獨孤良器','唐','御定全唐诗','yuding','','[]','皎潔沈泉水，熒煌照乘珠。沈非將寶契，還與不貪符。',72,'御定全唐詩/json/313.json','["皎潔沈泉水，熒煌照乘珠。沈非將寶契，還與不貪符。", "風折璿成浪，空涵影似浮。深看星併入，靜向月同無。", "光價憐時重，亡情通道樞。不應無脛至，自為暗投殊。"]'),
('yuding-8','雪席口占','高崇文','唐','御定全唐诗','yuding','','[]','崇文宗武不崇文，提戈出塞號將軍。',32,'御定全唐詩/json/313.json','["崇文宗武不崇文，提戈出塞號將軍。", "那個髇兒射雁落，白毛空裏亂紛紛。"]'),
('yuding-9','行縣至浮查山寺','羅珦','唐','御定全唐诗','yuding','','[]','三十年前此布衣，鹿鳴西上虎符歸。行時賓從過前寺，',40,'御定全唐詩/json/313.json','["三十年前此布衣，鹿鳴西上虎符歸。行時賓從過前寺，", "春風一宿琉璃地，自有泉聲愜素機。"]'),
('yuding-10','賦四相詩：中書令漢陽王張柬之','皇甫澈','唐','御定全唐诗','yuding','','[]','周曆革元命，天步值艱阻。烈烈張漢陽，左袒清諸武。',72,'御定全唐詩/json/313.json','["周曆革元命，天步值艱阻。烈烈張漢陽，左袒清諸武。", "休明神器正，文物舊儀睹。南向翊大君，西宮朝聖母。", "茂勳鏤鐘鼎，鴻勞食茅土。至今稱五王，卓立邁萬古。"]'),
('yuding-11','賦四相詩：中書令鐘紹京','皇甫澈','唐','御定全唐诗','yuding','','[]','景龍仙駕遠，中禁奸釁結。謀猷葉聖朝，披鱗奮英節。',72,'御定全唐詩/json/313.json','["景龍仙駕遠，中禁奸釁結。謀猷葉聖朝，披鱗奮英節。", "青宮閶闔啟，滌穢氛沴滅。紫氣重昭回，皇天新日月。", "從容廟堂上，肅穆人神悅。唐元佐命功，輝煥何烈烈。"]'),
('yuding-12','賦四相詩：禮部尚書門下侍郎平章事李峴','皇甫澈','唐','御定全唐诗','yuding','','[]','時來遇明聖，道濟甯邦國。猗歟瑚璉器，竭我股肱力。',72,'御定全唐詩/json/313.json','["時來遇明聖，道濟甯邦國。猗歟瑚璉器，竭我股肱力。", "進賢黜不肖，錯枉舉諸直。宦官既卻坐，權奸亦移職。", "載踐每若驚，三已無慍色。昭昭垂憲章，來世實作則。"]'),
('yuding-13','賦四相詩：門下侍郎平章事王縉','皇甫澈','唐','御定全唐诗','yuding','','[]','舟楫濟巨川，山河資秀氣。服膺究儒業，屈指取高位。',72,'御定全唐詩/json/313.json','["舟楫濟巨川，山河資秀氣。服膺究儒業，屈指取高位。", "北征戮驕悍，東守輯攜貳。論道致巍巍，持衡無事事。", "知己不易遇，宰相固有器。瞻事華壁中，來者誰其嗣。"]'),
('yuding-14','上巳泛舟得遲字','張登','唐','御定全唐诗','yuding','','[]','令節推元巳，天涯喜有期。初筵臨泛地，舊俗祓禳時。',72,'御定全唐詩/json/313.json','["令節推元巳，天涯喜有期。初筵臨泛地，舊俗祓禳時。", "枉渚潮新上，殘春日正遲。竹枝游女曲，桃葉渡江詞。", "風鷁今方退，沙鷗亦未疑。且同山簡醉，倒載莫褰帷。"]'),
('yuding-15','送王主簿游南海','張登','唐','御定全唐诗','yuding','','[]','平生推久要，留滯共三年。明日東南路，窮荒霧露天。',72,'御定全唐詩/json/313.json','["平生推久要，留滯共三年。明日東南路，窮荒霧露天。", "曠懷常寄酒，素業不言錢。道在貧非病，時來醜亦妍。", "過山乘蠟屐，涉海附樓船。行矣無為恨，宗門有大賢。"]'),
('yuding-16','重陽宴集同用寒字','張登','唐','御定全唐诗','yuding','','[]','錫宴逢佳節，窮荒亦共歡。恩深百日澤，雨借九秋寒。',72,'御定全唐詩/json/313.json','["錫宴逢佳節，窮荒亦共歡。恩深百日澤，雨借九秋寒。", "望氣人謠洽，臨風客以難。座移山色在，杯盡菊香殘。", "欲識投醪遍，應從落帽看。還宵須命燭，舉首謝三官。"]'),
('yuding-17','仲秋夜郡內西亭對月','張登','唐','御定全唐诗','yuding','','[]','天高月滿影悠悠，一夜炎荒並覺秋。氣與露清凝眾草，',40,'御定全唐詩/json/313.json','["天高月滿影悠悠，一夜炎荒並覺秋。氣與露清凝眾草，", "□直西傾河漢曙，遺風猶想武昌樓。"]'),
('yuding-18','冬至夜郡齋宴別前華陰盧主簿','張登','唐','御定全唐诗','yuding','','[]','虎宿方冬至，雞人積夜籌。相逢一尊酒，共結兩鄉愁。',48,'御定全唐詩/json/313.json','["虎宿方冬至，雞人積夜籌。相逢一尊酒，共結兩鄉愁。", "王儉花為府，盧諶幄內璆。明朝更臨水，悵望嶺南流。"]'),
('yuding-19','小雪日戲題絕句','張登','唐','御定全唐诗','yuding','','[]','甲子徒推小雪天，刺梧猶綠槿花然。',32,'御定全唐詩/json/313.json','["甲子徒推小雪天，刺梧猶綠槿花然。", "融和長養無時歇，卻是炎洲雨露偏。"]'),
('yuding-20','招客游寺','張登','唐','御定全唐诗','yuding','','[]','江城吏散卷春陰，山寺鳴鐘隔雨深。',32,'御定全唐詩/json/313.json','["江城吏散卷春陰，山寺鳴鐘隔雨深。", "招取遺民赴僧社，竹堂分坐靜看心。"]'),
('yuding-21','句','張登','唐','御定全唐诗','yuding','','[]','孤高齊帝石，蕭灑晉亭峰。。',25,'御定全唐詩/json/313.json','["孤高齊帝石，蕭灑晉亭峰。。", "境曠窮山外，城標漲海頭。"]'),
('yuding-22','陪韓退之、竇貽、周同尋劉尊師不遇，得師字','韋執中','唐','御定全唐诗','yuding','','[]','早尚逍遙境，常懷汗漫期。星郎同訪道，羽客杳何之。',48,'御定全唐詩/json/313.json','["早尚逍遙境，常懷汗漫期。星郎同訪道，羽客杳何之。", "物外求仙侶，人間失我師。不知柯爛者，何處看圍棋。"]'),
('yuding-23','尋人偶題','邵真','唐','御定全唐诗','yuding','','[]','日昃不復午，落花難歸樹。人生能幾何，莫厭相逢遇。',24,'御定全唐詩/json/313.json','["日昃不復午，落花難歸樹。人生能幾何，莫厭相逢遇。"]'),
('yuding-24','牆陰殘雪','何頻瑜','唐','御定全唐诗','yuding','','[]','積雪還因地，牆陰久尚殘。影添斜月白，光借夕陽寒。',72,'御定全唐詩/json/313.json','["積雪還因地，牆陰久尚殘。影添斜月白，光借夕陽寒。", "皎潔開簾近，清熒步履看。狀花飛著樹，如玉不成盤。", "冰薄方寧及，霜濃比亦難。誰憐高臥處，歲暮歎袁安。"]'),
('yuding-25','題度支雜事典庭中柏樹','駱浚','唐','御定全唐诗','yuding','','[]','幹聳一條青玉直，葉鋪千疊綠雲低。',32,'御定全唐詩/json/313.json','["幹聳一條青玉直，葉鋪千疊綠雲低。", "爭如燕雀偏巢此，卻是鴛鴦不得棲。"]'),
('yuding-26','梢雲','羅讓','唐','御定全唐诗','yuding','','[]','殊質資靈貺，淩空發瑞雲。梢梢含樹彩，鬱鬱動霞文。',72,'御定全唐詩/json/313.json','["殊質資靈貺，淩空發瑞雲。梢梢含樹彩，鬱鬱動霞文。", "不比因風起，全非觸石分。葉光閑泛灩，枝杪靜氛氳。", "隱見心無宰，裴回慶自君。翻飛如可托，長願在橫汾。"]'),
('yuding-27','閏月定四時','羅讓','唐','御定全唐诗','yuding','','[]','月閏隨寒暑，疇人定職司。餘分將考日，積算自成時。',72,'御定全唐詩/json/313.json','["月閏隨寒暑，疇人定職司。餘分將考日，積算自成時。", "律候行宜表，陰陽運不欺。氣熏灰管驗，數扐卦辭推。", "六律文明序，三年理暗移。當知歲功立，唯是奉無私。"]'),
('yuding-0','享文恭太子廟樂章','陳京','唐','御定全唐诗','yuding','','[]','歌以德發，聲以樂貴。樂善名存，追仙禮異。',40,'御定全唐詩/json/314.json','["歌以德發，聲以樂貴。樂善名存，追仙禮異。", "鸞旌拱修，鳳鳴合次。神聽皇慈，仲月皆至。"]'),
('yuding-1','步虛詞十九首','韋渠牟','唐','御定全唐诗','yuding','','[]','玉簡真人降，金書道籙通。煙霞方蔽日，雲雨已生風。',576,'御定全唐詩/json/314.json','["玉簡真人降，金書道籙通。煙霞方蔽日，雲雨已生風。", "四極威儀異，三天使命同。那將人世戀，不去上清宮。", "羽駕正翩翩，雲鴻最自然。霞冠將月曉，珠佩與星連。", "鏤玉留新訣，雕金得舊編。不知飛鸞鶴，更有幾人仙。", "上帝求仙使，真符取玉郎。三才閑布象，二景郁生光。", "騎吏排龍虎，笙歌走鳳凰。天高人不見，暗入白雲鄉。", "鸞鶴共裴回，仙官使者催。香花三洞啟，風雨百神來。", "鳳篆文初定，龍泥印已開。何須生羽翼，始得上瑤台。", "羽節忽排煙，蘇君已得仙。命風驅日月，縮地走山川。", "幾處留丹灶，何時種玉田。一朝騎白虎，直上紫微天。", "靜發降靈香，思神意智長。虎存時促步，龍想更成章。", "扣齒風雷響，挑燈日月光。仙雲在何處，仿佛滿空堂。", "幾度遊三洞，何方召百神。風雲皆守一，龍虎亦全真。", "執節仙童小，燒香玉女春。應須絕岩內，委曲問皇人。", "上法杳無營，玄修似有情。道宮瓊作想，真帝玉為名。", "召嶽馳旌節，驅雷發吏兵。雲車降何處，齋室有仙卿。", "羽衛一何鮮，香雲起暮煙。方朝太素帝，更向玉清天。", "鳳曲凝猶吹，龍驂儼欲前。真文幾時降，知在永和年。", "大道何年學，真符此日催。還持金作印，未要玉為台。", "羽節分明授，霞衣整頓裁。應緣五雲使，教上列仙來。", "獨自授金書，蕭條詠紫虛。龍行還當馬，雲起自成車。", "九轉風煙合，千年井灶餘。參差從太一，壽等混元初。", "道學已通神，香花會女真。霞床珠鬥帳，金薦玉輿輪。", "一室心偏靜，三天夜正春。靈官竟誰降，仙相有夫人。"]'),
('yuding-2','覽外生盧綸詩，因以示此','韋渠牟','唐','御定全唐诗','yuding','','[]','衛玠清談性最強，明時獨拜正員郎。關心珠玉曾無價，',40,'御定全唐詩/json/314.json','["衛玠清談性最強，明時獨拜正員郎。關心珠玉曾無價，", "終期內殿聯詩句，共汝朝天會柏梁。"]'),
('yuding-3','贈竇五判官','韋渠牟','唐','御定全唐诗','yuding','','[]','故舊相逢三兩家，愛君兄弟有聲華。文輝錦彩珠垂露，',40,'御定全唐詩/json/314.json','["故舊相逢三兩家，愛君兄弟有聲華。文輝錦彩珠垂露，", "終須撰取新詩品，更比芙蓉出水花。"]'),
('yuding-4','湖上閒居','竇參','唐','御定全唐诗','yuding','','[]','避影將息陰，自然知音稀。向來深林中，偶亦有所窺。',60,'御定全唐詩/json/314.json','["避影將息陰，自然知音稀。向來深林中，偶亦有所窺。", "飛鳥口銜食，引雛上高枝。高枝但各有，安知宜不宜。", "止止複何雲，物情何自私。"]'),
('yuding-5','遷謫江表久未歸','竇參','唐','御定全唐诗','yuding','','[]','一自經放逐，裴回無所從。便為寒山雲，不得隨飛龍。',84,'御定全唐詩/json/314.json','["一自經放逐，裴回無所從。便為寒山雲，不得隨飛龍。", "名豈不欲保，歸豈不欲早。苟無三月資，難適千里道。", "離心與羈思，終日常草草。人生年幾齊，憂苦即先老。", "誰能假羽翼，使我暢懷抱。"]'),
('yuding-6','登潛山觀','竇參','唐','御定全唐诗','yuding','','[]','山勢欲相抱，一條微徑盤。攀蘿歇複行，始得淩仙壇。',120,'御定全唐詩/json/314.json','["山勢欲相抱，一條微徑盤。攀蘿歇複行，始得淩仙壇。", "聞道葛夫子，此中煉還丹。丹成五色光，服之生羽翰。", "靈草空自綠，餘霞誰共餐。至今步虛處，猶有孤飛鸞。", "幽幽古殿門，下壓浮雲端。萬丈水聲落，四時松色寒。", "既入無何鄉，轉嫌人事難。終當遠塵俗，高臥從所安。"]'),
('yuding-7','淮西席上醉歌','盧群','唐','御定全唐诗','yuding','','[]','祥瑞不在鳳凰麒麟，太平須得邊將忠臣。衛霍真誠奉主，',43,'御定全唐詩/json/314.json','["祥瑞不在鳳凰麒麟，太平須得邊將忠臣。衛霍真誠奉主，", "但得百寮師長肝膽，不用三軍羅綺金銀。"]'),
('yuding-8','天池晚棹','韋皋','唐','御定全唐诗','yuding','','[]','雨霽天池生意足，花間誰詠採蓮曲。舟浮十裏芰荷香，',40,'御定全唐詩/json/314.json','["雨霽天池生意足，花間誰詠採蓮曲。舟浮十裏芰荷香，", "扣舷歸載月黃昏，直至更深不假燭。"]'),
('yuding-9','贈何遐','韋皋','唐','御定全唐诗','yuding','','[]','腰間寶劍七星文，掌上彎弓掛六鈞。',32,'御定全唐詩/json/314.json','["腰間寶劍七星文，掌上彎弓掛六鈞。", "箭發□雲雙雁落，始知秦地有將軍。"]'),
('yuding-10','憶玉簫','韋皋','唐','御定全唐诗','yuding','','[]','黃雀銜來已數春，別時留解贈佳人。',32,'御定全唐詩/json/314.json','["黃雀銜來已數春，別時留解贈佳人。", "長江不見魚書至，為遣相思夢入秦。"]'),
('yuding-11','觀翟玉妓','李願','唐','御定全唐诗','yuding','','[]','女郎閨閣春，抱瑟坐花茵。豔粉宜斜燭，羞蛾慘向人。',48,'御定全唐詩/json/314.json','["女郎閨閣春，抱瑟坐花茵。豔粉宜斜燭，羞蛾慘向人。", "寄情搖玉柱，流眄整羅巾。幸以芳香袖，承君宛轉塵。"]'),
('yuding-12','思婦','李願','唐','御定全唐诗','yuding','','[]','良人久不至，惟恨錦屏孤。憔悴衣寬日，空房問女巫。',24,'御定全唐詩/json/314.json','["良人久不至，惟恨錦屏孤。憔悴衣寬日，空房問女巫。"]'),
('yuding-13','徐州使院賦','王智興','唐','御定全唐诗','yuding','','[]','三十年前老健兒，剛被郎中遣作詩。',32,'御定全唐詩/json/314.json','["三十年前老健兒，剛被郎中遣作詩。", "江南花柳從君詠，塞北煙塵我獨知。"]'),
('yuding-14','茶山詩','袁高','唐','御定全唐诗','yuding','','[]','禹貢通遠俗，所圖在安人。後王失其本，職吏不敢陳。',240,'御定全唐詩/json/314.json','["禹貢通遠俗，所圖在安人。後王失其本，職吏不敢陳。", "亦有奸佞者，因茲欲求伸。動生千金費，日使萬姓貧。", "我來顧渚源，得與茶事親。氓輟耕農耒，采采實苦辛。", "一夫旦當役，盡室皆同臻。捫葛上欹壁，蓬頭入荒榛。", "終朝不盈掬，手足皆鱗皴。悲嗟遍空山，草木為不春。", "陰嶺芽未吐，使者牒已頻。心爭造化功，走挺糜鹿均。", "選納無晝夜，搗聲昏繼晨。眾工何枯櫨，俯視彌傷神。", "皇帝尚巡狩，東郊路多堙。周回繞天涯，所獻愈艱勤。", "況減兵革困，重茲固疲民。未知供禦餘，誰合分此珍。", "顧省忝邦守，又慚複因循。茫茫滄海間，丹憤何由申。"]'),
('yuding-15','送惟詳律師自越之義興','崔子向','唐','御定全唐诗','yuding','','[]','陽羨諸峰頂，何曾異剡山。雨晴人到寺，木落夜開關。',48,'御定全唐詩/json/314.json','["陽羨諸峰頂，何曾異剡山。雨晴人到寺，木落夜開關。", "縫衲紗燈亮，看心錫仗閑。西方知有社，未得與師還。"]'),
('yuding-16','上鮑大夫','崔子向','唐','御定全唐诗','yuding','','[]','行盡江南塞北時，無人不誦鮑家詩。',32,'御定全唐詩/json/314.json','["行盡江南塞北時，無人不誦鮑家詩。", "東堂桂樹何年折，直至如今少一枝。"]'),
('yuding-17','題越王台','崔子向','唐','御定全唐诗','yuding','','[]','越井崗頭松柏老，越王臺上生秋草。',32,'御定全唐詩/json/314.json','["越井崗頭松柏老，越王臺上生秋草。", "古木多年無子孫，牛羊踐踏成官道。"]'),
('yuding-18','贈韓退之','張署','唐','御定全唐诗','yuding','','[]','九疑峰畔二江前，戀闕思鄉日抵年。白簡趨朝曾並命，',40,'御定全唐詩/json/314.json','["九疑峰畔二江前，戀闕思鄉日抵年。白簡趨朝曾並命，", "渙汗幾時流率土，扁舟西下共歸田。"]'),
('yuding-19','享惠昭太子廟樂章','歸登','唐','御定全唐诗','yuding','','[]','嘉薦既陳，祀事孔明。間歌在堂，萬舞在庭。',40,'御定全唐詩/json/314.json','["嘉薦既陳，祀事孔明。間歌在堂，萬舞在庭。", "外則盡物，內則盡誠。鳳笙如聞，歆其潔精。"]'),
('yuding-0','剡溪行卻寄新別者','朱放','唐','御定全唐诗','yuding','','[]','潺湲寒溪上，自此成離別。回首望歸人，移舟逢暮雪。',48,'御定全唐詩/json/315.json','["潺湲寒溪上，自此成離別。回首望歸人，移舟逢暮雪。", "頻行識草樹，漸老傷年發。唯有白雲心，為向東山月。"]'),
('yuding-1','九日陪劉中丞宴昌樂寺送梁廷評','朱放','唐','御定全唐诗','yuding','','[]','獨坐三台妙，重陽百越間。水心觀遠俗，霜氣入秋山。',48,'御定全唐詩/json/315.json','["獨坐三台妙，重陽百越間。水心觀遠俗，霜氣入秋山。", "不棄遺簪舊，寧辭落帽還。仍聞西上客，咫尺謁天顏。"]'),
('yuding-2','經故賀賓客鏡湖道士觀','朱放','唐','御定全唐诗','yuding','','[]','已得歸鄉里，逍遙一外臣。那隨流水去，不待鏡湖春。',48,'御定全唐詩/json/315.json','["已得歸鄉里，逍遙一外臣。那隨流水去，不待鏡湖春。", "雪裏登山屐，林間漉酒巾。空餘道士觀，誰是學仙人。"]'),
('yuding-3','送著公歸越','朱放','唐','御定全唐诗','yuding','','[]','誰能愁此別，到越會相逢。長憶雲門寺，門前千萬峰。',48,'御定全唐詩/json/315.json','["誰能愁此別，到越會相逢。長憶雲門寺，門前千萬峰。", "石床埋積雪，山路倒枯松。莫學白道士，無人知去蹤。"]'),
('yuding-4','秣陵送客入京','朱放','唐','御定全唐诗','yuding','','[]','秣陵春已至，君去學歸鴻。綠水琴聲切，青袍草色同。',48,'御定全唐詩/json/315.json','["秣陵春已至，君去學歸鴻。綠水琴聲切，青袍草色同。", "鳥喧金穀樹，花滿洛陽宮。日日相思處，江邊楊柳風。"]'),
('yuding-5','靈門寺贈靈一上人','朱放','唐','御定全唐诗','yuding','','[]','所思勞旦夕，惆悵去湘東。禪客知何在，春山幾處同。',48,'御定全唐詩/json/315.json','["所思勞旦夕，惆悵去湘東。禪客知何在，春山幾處同。", "獨行殘雪裏，相見暮雲中。請住東林寺，彌年事遠公。"]'),
('yuding-6','江上送別','朱放','唐','御定全唐诗','yuding','','[]','浦邊新見柳搖時，北客相逢只自悲。惆悵空知思後會，',40,'御定全唐詩/json/315.json','["浦邊新見柳搖時，北客相逢只自悲。惆悵空知思後會，", "向夕孤城分首處，寂寥橫笛為君吹。"]'),
('yuding-7','歸桐廬舊居寄嚴長史','朱放','唐','御定全唐诗','yuding','','[]','昨辭天子棹歸舟，家在桐廬憶舊丘。三月暖時花競發，',40,'御定全唐詩/json/315.json','["昨辭天子棹歸舟，家在桐廬憶舊丘。三月暖時花競發，", "或在醉中逢夜雪，懷賢應向剡川遊。"]'),
('yuding-8','竹','朱放','唐','御定全唐诗','yuding','','[]','青林何森然，沉沉獨曙前。出牆同淅瀝，開戶滿嬋娟。',120,'御定全唐詩/json/315.json','["青林何森然，沉沉獨曙前。出牆同淅瀝，開戶滿嬋娟。", "籜卷初呈粉，苔侵亂上錢。疏中思水過，深處若山連。", "疊夜常棲露，清朝乍有蟬。砌陰迎緩策，簷翠對欹眠。", "迸筍雙分箭，繁梢一向偏。月過驚散雪，風動極聞泉。", "幽谷添詩譜，高人欲制篇。蕭蕭意何恨，不獨往湘川。"]'),
('yuding-9','銅雀妓','朱放','唐','御定全唐诗','yuding','','[]','恨唱歌聲咽，愁翻舞袖遲。西陵日欲暮，是妾斷腸時。',24,'御定全唐詩/json/315.json','["恨唱歌聲咽，愁翻舞袖遲。西陵日欲暮，是妾斷腸時。"]'),
('yuding-10','毗陵留別','朱放','唐','御定全唐诗','yuding','','[]','別離非一處，此處最傷情。白髮將春草，相隨日日生。',24,'御定全唐詩/json/315.json','["別離非一處，此處最傷情。白髮將春草，相隨日日生。"]'),
('yuding-11','題竹林寺','朱放','唐','御定全唐诗','yuding','','[]','歲月人間促，煙霞此地多。殷勤竹林寺，能得幾回過。',24,'御定全唐詩/json/315.json','["歲月人間促，煙霞此地多。殷勤竹林寺，能得幾回過。"]'),
('yuding-12','答陸澧','朱放','唐','御定全唐诗','yuding','','[]','松葉堪為酒，春來釀幾多。不辭山路遠，踏雪也相過。',24,'御定全唐詩/json/315.json','["松葉堪為酒，春來釀幾多。不辭山路遠，踏雪也相過。"]'),
('yuding-13','楊子津送人','朱放','唐','御定全唐诗','yuding','','[]','今朝楊子津，忽見五溪人。老病無餘事，丹砂乞五斤。',24,'御定全唐詩/json/315.json','["今朝楊子津，忽見五溪人。老病無餘事，丹砂乞五斤。"]'),
('yuding-14','山中謁皇甫曾','朱放','唐','御定全唐诗','yuding','','[]','尋源路已盡，笑入白雲間。不解乘軺客，那知有此山。',24,'御定全唐詩/json/315.json','["尋源路已盡，笑入白雲間。不解乘軺客，那知有此山。"]'),
('yuding-15','剡山夜月','朱放','唐','御定全唐诗','yuding','','[]','月在沃洲山上，人歸剡縣溪邊。',28,'御定全唐詩/json/315.json','["月在沃洲山上，人歸剡縣溪邊。", "漠漠黃花覆水，時時白鷺驚船。"]'),
('yuding-16','九日與楊凝、崔淑期登江上山會有故不得往因贈之','朱放','唐','御定全唐诗','yuding','','[]','欲從攜手登高去，一到門前意已無。',32,'御定全唐詩/json/315.json','["欲從攜手登高去，一到門前意已無。", "那得更將頭上發，學他年少插茱萸。"]'),
('yuding-17','山中聽子規','朱放','唐','御定全唐诗','yuding','','[]','幽人自愛山中宿，又近葛洪丹井西。',32,'御定全唐詩/json/315.json','["幽人自愛山中宿，又近葛洪丹井西。", "窗中有個長松樹，半夜子規來上啼。"]'),
('yuding-18','亂後經淮陰岸','朱放','唐','御定全唐诗','yuding','','[]','荒村古岸誰家在，野水浮雲處處愁。',32,'御定全唐詩/json/315.json','["荒村古岸誰家在，野水浮雲處處愁。", "唯有河邊衰柳樹，蟬聲相送到揚州。"]'),
('yuding-19','送張山人','朱放','唐','御定全唐诗','yuding','','[]','知君住處足風煙，古寺荒村在眼前。',32,'御定全唐詩/json/315.json','["知君住處足風煙，古寺荒村在眼前。", "便欲移家逐君去，唯愁未有買山錢。"]'),
('yuding-20','別李季蘭','朱放','唐','御定全唐诗','yuding','','[]','古岸新花開一枝，岸傍花下有分離。',32,'御定全唐詩/json/315.json','["古岸新花開一枝，岸傍花下有分離。", "莫將羅袖拂花落，便是行人腸斷時。"]'),
('yuding-21','游石澗寺','朱放','唐','御定全唐诗','yuding','','[]','聞道幽深石澗寺，不逢流水亦難知。',32,'御定全唐詩/json/315.json','["聞道幽深石澗寺，不逢流水亦難知。", "莫道山僧無伴侶，獼猴長在古松枝。"]'),
('yuding-22','新安所居答相訪人所居蕭使君為制','朱放','唐','御定全唐诗','yuding','','[]','謝公見我多愁疾，為我開門對碧山。',32,'御定全唐詩/json/315.json','["謝公見我多愁疾，為我開門對碧山。", "君若欲來看猿鳥，不須爭把桂枝攀。"]'),
('yuding-23','送魏校書','朱放','唐','御定全唐诗','yuding','','[]','長恨江南足別離，幾回相送複相隨。',32,'御定全唐詩/json/315.json','["長恨江南足別離，幾回相送複相隨。", "楊花撩亂撲流水，愁殺人行知不知。"]'),
('yuding-24','送溫台','朱放','唐','御定全唐诗','yuding','','[]','眇眇天涯君去時，浮雲流水自相隨。',32,'御定全唐詩/json/315.json','["眇眇天涯君去時，浮雲流水自相隨。", "人生一世長如客，何必今朝是別離。"]'),
('yuding-25','句','朱放','唐','御定全唐诗','yuding','','[]','愛彼雲外人，求取澗底泉。',25,'御定全唐詩/json/315.json','["愛彼雲外人，求取澗底泉。", "風吹芭蕉拆，鳥啄梧桐落。。"]'),
('yuding-0','古意','武元衡','唐','御定全唐诗','yuding','','[]','蜀國春與秋，岷江朝夕流。長波東接海，萬里至揚州。',60,'御定全唐詩/json/316.json','["蜀國春與秋，岷江朝夕流。長波東接海，萬里至揚州。", "開門面淮甸，楚俗饒歡宴。舞榭黃金梯，歌樓白雲面。", "蕩子未言歸，池塘月如練。"]'),
('yuding-1','塞下曲','武元衡','唐','御定全唐诗','yuding','','[]','草枯馬蹄輕，角弓勁如石。驕虜初欲來，風塵暗南國。',72,'御定全唐詩/json/316.json','["草枯馬蹄輕，角弓勁如石。驕虜初欲來，風塵暗南國。", "走檄召都尉，星火剿羌狄。吾身許報主，何暇避鋒鏑。", "白露濕鐵衣，半夜待攻擊。龍沙早立功，名向燕然勒。"]'),
('yuding-2','獨不見','武元衡','唐','御定全唐诗','yuding','','[]','荊門一柱觀，楚國三休殿。環佩儼神仙，輝光生顧盼。',84,'御定全唐詩/json/316.json','["荊門一柱觀，楚國三休殿。環佩儼神仙，輝光生顧盼。", "春風細腰舞，明月高堂宴。夢澤水連雲，渚宮花似霰。", "俄驚白日晚，始悟炎涼變。別島異波潮，離鴻分海縣。", "南北斷相聞，歎嗟獨不見。"]'),
('yuding-3','旬假南亭寄熊郎中','武元衡','唐','御定全唐诗','yuding','','[]','旬休屏戎事，涼雨北窗眠。江城一夜雨，萬里繞山川。',120,'御定全唐詩/json/316.json','["旬休屏戎事，涼雨北窗眠。江城一夜雨，萬里繞山川。", "草木散幽氣，池塘鳴早蟬。妍芳落春後，旅思生秋前。", "紅槿粲庭豔，綠蒲繁渚煙。行歌獨謠酌，坐發朱絲弦。", "哀玉不可扣，華燭徒湛然。聞君樂林臥，郡閣曠周旋。", "酬對龍象侶，灌注清泠泉。如何無礙智，猶苦病纏牽。"]'),
('yuding-4','晨興寄贈竇使君','武元衡','唐','御定全唐诗','yuding','','[]','江陵歲方晏，晨起眄庭柯。白露傷紅葉，清風斷綠蘿。',96,'御定全唐詩/json/316.json','["江陵歲方晏，晨起眄庭柯。白露傷紅葉，清風斷綠蘿。", "徇時真氣索，念遠懷憂多。夙昔樂山意，縱橫南浦波。", "有美嬋娟子，百慮攢雙蛾。緘情郁不舒，幽行駢複羅。", "為予歌苦寒，酌酒朱顏酡。世事浮雲變，功名將奈何。"]'),
('yuding-5','秋日對酒','武元衡','唐','御定全唐诗','yuding','','[]','行年過始衰，秋至獨先悲。事往憐神魄，感深滋涕洟。',168,'御定全唐詩/json/316.json','["行年過始衰，秋至獨先悲。事往憐神魄，感深滋涕洟。", "百憂紛在慮，一醉兀無思。寶瑟拂塵匣，徽音凝朱絲。", "幽圃蕙蘭氣，煙窗松桂姿。我乏濟時略，杖節撫藩維。", "山川大兵後，牢落空城池。驚沙猶振野，綠草生荒陂。", "物變風雨順，人懷天地慈。春耕事秋戰，戎馬去封陲。", "波瀾暗超忽，堅白亦磷緇。客有自嵩潁，重征棲隱期。", "丹訣學仙晚，白雲歸谷遲。君恩不可報，霜露繞南枝。"]'),
('yuding-6','安邑裏中秋懷寄高員外','武元衡','唐','御定全唐诗','yuding','','[]','原憲素非貧，嵇康自寡欲。守道識通窮，達命齊榮辱。',120,'御定全唐詩/json/316.json','["原憲素非貧，嵇康自寡欲。守道識通窮，達命齊榮辱。", "庭梧變蔥蒨，籬菊揚芳馥。墜葉翻夕霜，高堂瞬華燭。", "況茲寒夜永，複歎流年促。感物思殷勤，懷賢心躑躅。", "雄詞封禪草，麗句陽春曲。高德十年兄，異才千里足。", "咫尺邈雪霜，相望如瓊玉。欲識歲寒心，松筠更秋綠。"]'),
('yuding-7','送唐次','武元衡','唐','御定全唐诗','yuding','','[]','都門去馬嘶，灞水春流淺。青槐驛路長，白日離尊晚。',36,'御定全唐詩/json/316.json','["都門去馬嘶，灞水春流淺。青槐驛路長，白日離尊晚。", "望望煙景微，草色行人遠。"]'),
('yuding-8','秋夜雨中懷友','武元衡','唐','御定全唐诗','yuding','','[]','庭空雨鳴驕，天寒雁啼苦。青燈淡吐光，白髮悄無語。',40,'御定全唐詩/json/316.json','["庭空雨鳴驕，天寒雁啼苦。青燈淡吐光，白髮悄無語。", "幾年不與聯床吟，君方客吳我猶楚。"]'),
('yuding-9','望夫石','武元衡','唐','御定全唐诗','yuding','','[]','佳名望夫處，苔蘚封孤石。萬里水連天，巴江暮雲碧。',40,'御定全唐詩/json/316.json','["佳名望夫處，苔蘚封孤石。萬里水連天，巴江暮雲碧。", "湘妃泣下竹成斑，子規夜啼江樹白。"]'),
('yuding-10','行路難','武元衡','唐','御定全唐诗','yuding','','[]','君不見道傍廢井傍開花，原是昔年驕貴家。',67,'御定全唐詩/json/316.json','["君不見道傍廢井傍開花，原是昔年驕貴家。", "幾度美人來照影，濯纖笑引銀瓶綆。風飄雨散今奈何，", "休說編氓樸無恥，至竟終須合天理。非故敗他卻成此，"]'),
('yuding-11','長相思','武元衡','唐','御定全唐诗','yuding','','[]','長相思，隴雲愁，單于臺上望伊州。雁書絕，蟬鬢秋。',48,'御定全唐詩/json/316.json','["長相思，隴雲愁，單于臺上望伊州。雁書絕，蟬鬢秋。", "行人天一畔，暮雨海西頭。殷勤大河水，東注不還流。"]'),
('yuding-12','出塞作','武元衡','唐','御定全唐诗','yuding','','[]','夙駕逾人境，長驅出塞垣。邊風引去騎，胡沙拂征轅。',60,'御定全唐詩/json/316.json','["夙駕逾人境，長驅出塞垣。邊風引去騎，胡沙拂征轅。", "奏笳山月白，結陣瘴雲昏。雖雲風景異華夏，", "要須灑掃龍沙淨，歸謁明光一報恩。"]'),
('yuding-13','桃源行送友','武元衡','唐','御定全唐诗','yuding','','[]','武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。',96,'御定全唐詩/json/316.json','["武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。", "桃花兩邊種來久，流水一通何時有。垂條落蕊暗春風，", "時有仙鳥來銜花，曾無世人此攜手。可憐不知若為名，", "相見維舟登覽處，紅堤綠岸宛然成。多君此去從仙隱，"]'),
('yuding-14','長安敘懷寄崔十五','武元衡','唐','御定全唐诗','yuding','','[]','延首直城西，花飛綠草齊。迢遙隔山水，悵望思遊子。',136,'御定全唐詩/json/316.json','["延首直城西，花飛綠草齊。迢遙隔山水，悵望思遊子。", "百囀黃鸝細雨中，千條翠柳衡門裏。門對長安九衢路，", "漢家宮闕在中天，紫陌朝臣車馬連。蕭蕭霓旌合仙仗，", "無媒守儒行，榮悴紛相映。家甚長卿貧，身多公幹病。", "不知身病竟如何，懶向青山眠薜蘿。雞黍空多元伯惠，", "聞說唐生子孫在，何當一為問窮通。"]'),
('yuding-15','兵行褒斜谷作','武元衡','唐','御定全唐诗','yuding','','[]','古地接龜沙，邊風送征雁。霜明草正腓，峰逼日易晏。',72,'御定全唐詩/json/316.json','["古地接龜沙，邊風送征雁。霜明草正腓，峰逼日易晏。", "集旅布嵌谷，驅馬曆層澗。岷河源涉屢，蜀甸途行慣。", "矢橐弧室豈領軍，儋爵食祿由從宦。注意奏凱赴都畿，"]'),
('yuding-16','西亭早秋送徐員外','武元衡','唐','御定全唐诗','yuding','','[]','鼎鉉辭台座，麾幢領益州。曲池連月曉，橫角滿城秋。',48,'御定全唐詩/json/316.json','["鼎鉉辭台座，麾幢領益州。曲池連月曉，橫角滿城秋。", "有美皇華使，曾同白社遊。今年重相見，偏覺豔歌愁。"]'),
('yuding-17','送徐員外還京','武元衡','唐','御定全唐诗','yuding','','[]','九折朱輪動，三巴白露生。蕙蘭秋意晚，關塞別魂驚。',48,'御定全唐詩/json/316.json','["九折朱輪動，三巴白露生。蕙蘭秋意晚，關塞別魂驚。", "寶瑟連宵怨，金罍盡醉傾。旄頭星未落，分手轆轤鳴。"]'),
('yuding-18','送柳郎中裴起居','武元衡','唐','御定全唐诗','yuding','','[]','沱江水綠波，喧鳥去喬柯。南浦別離處，東風蘭杜多。',48,'御定全唐詩/json/316.json','["沱江水綠波，喧鳥去喬柯。南浦別離處，東風蘭杜多。", "長亭春婉娩，層漢路蹉跎。會有歸朝日，班超奈老何。"]'),
('yuding-19','八月十五酬從兄常望月有懷','武元衡','唐','御定全唐诗','yuding','','[]','坐愛圓景滿，況茲秋夜長。寒光生露草，夕韻出風篁。',48,'御定全唐詩/json/316.json','["坐愛圓景滿，況茲秋夜長。寒光生露草，夕韻出風篁。", "地遠驚金奏，天高失雁行。如何北樓望，不得共池塘。"]'),
('yuding-20','酬太常從兄留別','武元衡','唐','御定全唐诗','yuding','','[]','鄉路日茲始，征軒行複留。張騫隨漢節，王浚守刀州。',48,'御定全唐詩/json/316.json','["鄉路日茲始，征軒行複留。張騫隨漢節，王浚守刀州。", "澤國煙花度，銅梁霧雨愁。別離無可奈，萬恨錦江流。"]'),
('yuding-21','春日與諸公泛舟','武元衡','唐','御定全唐诗','yuding','','[]','千里雪山開，沱江春水來。駐帆雲縹緲，吹管鶴裴回。',48,'御定全唐詩/json/316.json','["千里雪山開，沱江春水來。駐帆雲縹緲，吹管鶴裴回。", "身外流年駛，尊前落景催。不應歸棹遠，明月在高臺。"]'),
('yuding-22','送兄歸洛使謁嚴司空','武元衡','唐','御定全唐诗','yuding','','[]','六歲蜀城守，千莖蓬鬢絲。憂心不自遣，骨肉又傷離。',48,'御定全唐詩/json/316.json','["六歲蜀城守，千莖蓬鬢絲。憂心不自遣，骨肉又傷離。", "楚峽饒雲雨，巴江足夢思。殷勤孔北海，時節易流移。"]'),
('yuding-23','同洛陽諸公餞盧起居','武元衡','唐','御定全唐诗','yuding','','[]','蕭條寒日晏，淒慘別魂驚。寶瑟無聲怨，金囊故贈輕。',48,'御定全唐詩/json/316.json','["蕭條寒日晏，淒慘別魂驚。寶瑟無聲怨，金囊故贈輕。", "赤墀方載筆，油幕尚言兵。暮宿青泥驛，煩君淚滿纓。"]'),
('yuding-24','台中題壁','武元衡','唐','御定全唐诗','yuding','','[]','柏台年未老，蓬鬢忽蒼蒼。無事裨明主，何心弄憲章。',48,'御定全唐詩/json/316.json','["柏台年未老，蓬鬢忽蒼蒼。無事裨明主，何心弄憲章。", "雀聲愁霰雪，鴻思恨關梁。會脫簪纓去，故山瑤草芳。"]'),
('yuding-25','江上寄隱者','武元衡','唐','御定全唐诗','yuding','','[]','歸舟不計程，江月屢虧盈。靄靄滄波路，悠悠離別情。',48,'御定全唐詩/json/316.json','["歸舟不計程，江月屢虧盈。靄靄滄波路，悠悠離別情。", "蒹葭連水國，鼙鼓近梁城。卻憶沿江叟，汀洲春草生。"]'),
('yuding-26','送嚴紳游蘭溪','武元衡','唐','御定全唐诗','yuding','','[]','剡嶺窮邊海，君遊別嶺西。暮雲秋水闊，寒雨夜猿啼。',48,'御定全唐詩/json/316.json','["剡嶺窮邊海，君遊別嶺西。暮雲秋水闊，寒雨夜猿啼。", "地僻秦人少，山多越路迷。蕭蕭驅匹馬，何處是蘭溪。"]'),
('yuding-27','秋思','武元衡','唐','御定全唐诗','yuding','','[]','秋室浩煙霧，風柳怨寒蜩。機杼夜聲切，蕙蘭芳意消。',48,'御定全唐詩/json/316.json','["秋室浩煙霧，風柳怨寒蜩。機杼夜聲切，蕙蘭芳意消。", "美人湘水曲，桂楫洞庭遙。常恐時光謝，蹉跎紅豔凋。"]'),
('yuding-28','夏日別盧太卿','武元衡','唐','御定全唐诗','yuding','','[]','漢水清且廣，江波渺複深。葉舟煙雨夜，之子別離心。',48,'御定全唐詩/json/316.json','["漢水清且廣，江波渺複深。葉舟煙雨夜，之子別離心。", "汀草結春怨，山雲連暝陰。年年南北淚，今古共沾襟。"]'),
('yuding-29','西亭題壁寄中書李相公','武元衡','唐','御定全唐诗','yuding','','[]','昏旦倦興寢，端憂力尚微。廉頗不覺老，蘧瑗始知非。',48,'御定全唐詩/json/316.json','["昏旦倦興寢，端憂力尚微。廉頗不覺老，蘧瑗始知非。", "授鉞虛三顧，持衡曠萬機。空餘蝴蝶夢，迢遞故山歸。"]'),
('yuding-30','八月十五夜與諸公錦樓望月得中字','武元衡','唐','御定全唐诗','yuding','','[]','玉輪初滿空，迥出錦城東。相向秦樓鏡，分飛碣石鴻。',48,'御定全唐詩/json/316.json','["玉輪初滿空，迥出錦城東。相向秦樓鏡，分飛碣石鴻。", "桂香隨窈窕，珠綴隔玲瓏。不及前秋月，圓輝鳳沼中。"]'),
('yuding-31','四川使宅有韋令公時孔雀存焉暇日與諸公同玩座中兼故府賓妓興嗟久之因賦此詩用廣其意','武元衡','唐','御定全唐诗','yuding','','[]','荀令昔居此，故巢留越禽。動搖金翠尾，飛舞碧梧陰。',48,'御定全唐詩/json/316.json','["荀令昔居此，故巢留越禽。動搖金翠尾，飛舞碧梧陰。", "上客徹瑤瑟，美人傷蕙心。會因南國使，得放海雲深。"]'),
('yuding-32','竇三中丞去歲有臺中五言四韻未及酬報今領黔南途經蜀門百里而近願言款覿封略間然因追曩篇持以贈之','武元衡','唐','御定全唐诗','yuding','','[]','在昔謬司憲，常僚惟有君。報恩如皎日，致位等青雲。',48,'御定全唐詩/json/316.json','["在昔謬司憲，常僚惟有君。報恩如皎日，致位等青雲。", "削稿書難見，除苛事早吟。雙旌不可駐，風雪路岐分。"]'),
('yuding-33','春分與諸公同宴呈陸三十四郎中','武元衡','唐','御定全唐诗','yuding','','[]','南國宴佳賓，交情老倍親。月慚紅燭淚，花笑白頭人。',48,'御定全唐詩/json/316.json','["南國宴佳賓，交情老倍親。月慚紅燭淚，花笑白頭人。", "寶瑟常餘怨，瓊枝不讓春。更聞歌子夜，桃李豔妝新。"]'),
('yuding-34','津梁寺採新茶與幕中諸公遍賞芳香尤異因題四韻兼呈陸郎中','武元衡','唐','御定全唐诗','yuding','','[]','靈州碧岩下，荑英初散芳。塗塗猶宿露，采采不盈筐。',48,'御定全唐詩/json/316.json','["靈州碧岩下，荑英初散芳。塗塗猶宿露，采采不盈筐。", "陰竇藏煙濕，單衣染焙香。幸將調鼎味，一為奏明光。"]'),
('yuding-35','元和癸巳余領蜀之七年奉詔徵還二月二十八日清明途經百牢關因題石門洞','武元衡','唐','御定全唐诗','yuding','','[]','昔佩兵符去，今持相印還。天光臨井絡，春物度巴山。',48,'御定全唐詩/json/316.json','["昔佩兵符去，今持相印還。天光臨井絡，春物度巴山。", "鳥道青冥外，風泉洞壑間。何慚班定遠，辛苦玉門關。"]'),
('yuding-36','夕次潘山下','武元衡','唐','御定全唐诗','yuding','','[]','南國獨行日，三巴春草齊。漾波歸海疾，危棧入雲迷。',48,'御定全唐詩/json/316.json','["南國獨行日，三巴春草齊。漾波歸海疾，危棧入雲迷。", "錦穀嵐煙裏，刀州晚照西。旅情方浩蕩，蜀魄滿林啼。"]'),
('yuding-37','夏日對雨寄朱放拾遺','武元衡','唐','御定全唐诗','yuding','','[]','才非穀永傳，無意謁王侯。小暑金將伏，微涼麥正秋。',48,'御定全唐詩/json/316.json','["才非穀永傳，無意謁王侯。小暑金將伏，微涼麥正秋。", "遠山欹枕見，暮雨閉門愁。更憶東林寺，詩家第一流。"]'),
('yuding-38','早春送歐陽煉師歸山','武元衡','唐','御定全唐诗','yuding','','[]','雙鶴五雲車，初辭漢帝家。人寰新甲子，天路舊煙霞。',48,'御定全唐詩/json/316.json','["雙鶴五雲車，初辭漢帝家。人寰新甲子，天路舊煙霞。", "羽節臨風駐，霓裳逐雨斜。昆侖有琪樹，相憶寄瑤華。"]'),
('yuding-39','長安春望','武元衡','唐','御定全唐诗','yuding','','[]','宿雨淨煙霞，春風綻百花。綠楊中禁路，朱戟五侯家。',48,'御定全唐詩/json/316.json','["宿雨淨煙霞，春風綻百花。綠楊中禁路，朱戟五侯家。", "草色金堤晚，鶯聲禦柳斜。無媒猶未達，應共惜年華。"]'),
('yuding-40','經嚴秘校維故宅','武元衡','唐','御定全唐诗','yuding','','[]','掩淚山陽宅，生涯此路窮。香銷芸閣閉，星落草堂空。',48,'御定全唐詩/json/316.json','["掩淚山陽宅，生涯此路窮。香銷芸閣閉，星落草堂空。", "麗藻浮名裏，哀聲夕照中。不堪投釣處，鄰笛怨春風。"]'),
('yuding-41','秋夜寄江南舊游','武元衡','唐','御定全唐诗','yuding','','[]','寥落九秋晚，端憂時物殘。隔林螢影度，出禁漏聲寒。',48,'御定全唐詩/json/316.json','["寥落九秋晚，端憂時物殘。隔林螢影度，出禁漏聲寒。", "愁雨洞房掩，孤燈遙夜闌。懷賢夢南國，興盡水漫漫。"]'),
('yuding-42','送陸書還吳','武元衡','唐','御定全唐诗','yuding','','[]','君住包山下，何年入帝鄉。成名歸舊業，歎別見秋光。',48,'御定全唐詩/json/316.json','["君住包山下，何年入帝鄉。成名歸舊業，歎別見秋光。", "橘柚吳洲遠，蘆花楚水長。我行經此路，京口向雲陽。"]'),
('yuding-43','山中月夜寄朱張二舍人','武元衡','唐','御定全唐诗','yuding','','[]','午夜更漏裏，九重霄漢間。月華雲闕迥，秋色鳳池閑。',48,'御定全唐詩/json/316.json','["午夜更漏裏，九重霄漢間。月華雲闕迥，秋色鳳池閑。", "禦錦通清禁，天書出暗關。嵇康不求達，終歲在空山。"]'),
('yuding-44','送馮諫議赴河北宣慰','武元衡','唐','御定全唐诗','yuding','','[]','漢代衣冠盛，堯年雨露多。恩榮辭紫禁，冰雪渡黃河。',48,'御定全唐詩/json/316.json','["漢代衣冠盛，堯年雨露多。恩榮辭紫禁，冰雪渡黃河。", "待詔孤城啟，宣風萬歲和。今宵燕分野，應見使星過。"]'),
('yuding-45','夜坐聞雨寄嚴十少府','武元衡','唐','御定全唐诗','yuding','','[]','多負雲霄志，生涯歲序侵。風翻涼葉亂，雨滴洞房深。',48,'御定全唐詩/json/316.json','["多負雲霄志，生涯歲序侵。風翻涼葉亂，雨滴洞房深。", "迢遞三秋夢，殷勤獨夜心。懷賢不覺寐，清磬發東林。"]'),
('yuding-46','資聖寺賁法師晚春茶會','武元衡','唐','御定全唐诗','yuding','','[]','虛室晝常掩，心源知悟空。禪庭一雨後，蓮界萬花中。',48,'御定全唐詩/json/316.json','["虛室晝常掩，心源知悟空。禪庭一雨後，蓮界萬花中。", "時節流芳暮，人天此會同。不知方便理，何路出樊籠。"]'),
('yuding-47','慈恩寺起上人院','武元衡','唐','御定全唐诗','yuding','','[]','禪堂支許同，清論道源窮。起滅秋雲盡，虛無夕靄空。',48,'御定全唐詩/json/316.json','["禪堂支許同，清論道源窮。起滅秋雲盡，虛無夕靄空。", "池澄山倒影，林動葉翻風。他日焚香待，還來禮惠聰。"]'),
('yuding-48','送魏正則擢第歸江陵','武元衡','唐','御定全唐诗','yuding','','[]','客路商山外，離筵小暑前。高文常獨步，折桂及齠年。',48,'御定全唐詩/json/316.json','["客路商山外，離筵小暑前。高文常獨步，折桂及齠年。", "關國通秦限，波濤隔漢川。叨同會府選，分手倍依然。"]'),
('yuding-49','酬韓弇歸崖見寄','武元衡','唐','御定全唐诗','yuding','','[]','惆悵人間事，東山遂獨遊。露凝瑤草晚，魚戲石潭秋。',48,'御定全唐詩/json/316.json','["惆悵人間事，東山遂獨遊。露凝瑤草晚，魚戲石潭秋。", "軒冕應相待，煙霞莫遽留。君看仲連意，功立始滄洲。"]'),
('yuding-50','河東贈別煉師','武元衡','唐','御定全唐诗','yuding','','[]','多累有行役，相逢秋節分。遊人甘失路，野鶴亦離群。',48,'御定全唐詩/json/316.json','["多累有行役，相逢秋節分。遊人甘失路，野鶴亦離群。", "戎馬犯邊壘，天兵屯塞雲。孔璋才素健，羽檄定紛紛。"]'),
('yuding-51','秋日將赴江上，楊弘微時任鳳翔，寄詩別','武元衡','唐','御定全唐诗','yuding','','[]','寂寞兩相阻，悠悠南北心。燕驚滄海遠，鴻避朔雲深。',48,'御定全唐詩/json/316.json','["寂寞兩相阻，悠悠南北心。燕驚滄海遠，鴻避朔雲深。", "夜夢江亭月，離憂隴樹陰。兼秋無限思，惆悵屬瑤琴。"]'),
('yuding-52','夏與熊王二秀才同宿僧院','武元衡','唐','御定全唐诗','yuding','','[]','共將纓上塵，來問雪山人。世網從知累，禪心自證真。',48,'御定全唐詩/json/316.json','["共將纓上塵，來問雪山人。世網從知累，禪心自證真。", "境空宜入夢，藤古不留春。一聽林公法，靈嘉願寄身。"]'),
('yuding-53','宜陽所居白蜀葵答詠柬諸公','武元衡','唐','御定全唐诗','yuding','','[]','冉冉眾芳歇，亭亭虛室前。敷榮時已背，幽賞地宜偏。',48,'御定全唐詩/json/316.json','["冉冉眾芳歇，亭亭虛室前。敷榮時已背，幽賞地宜偏。", "紅豔世方重，素華徒可憐。何當君子願，知不競喧妍。"]'),
('yuding-54','送寇侍禦司馬之明州','武元衡','唐','御定全唐诗','yuding','','[]','鬥酒上河梁，驚魂去越鄉。地窮滄海闊，雲入剡山長。',48,'御定全唐詩/json/316.json','["鬥酒上河梁，驚魂去越鄉。地窮滄海闊，雲入剡山長。", "蓮唱蒲萄熟，人煙橘柚香。蘭亭應駐楫，今古共風光。"]'),
('yuding-55','送嚴侍禦','武元衡','唐','御定全唐诗','yuding','','[]','巴檄故人去，蒼蒼楓樹林。雲山千里合，霧雨四時陰。',48,'御定全唐詩/json/316.json','["巴檄故人去，蒼蒼楓樹林。雲山千里合，霧雨四時陰。", "峽路猿聲斷，桃源犬吠深。不須貪勝賞，漢節待南侵。"]'),
('yuding-56','酬元十二','武元衡','唐','御定全唐诗','yuding','','[]','偶尋烏府客，同醉習家池。積雪初迷徑，孤雲遂失期。',48,'御定全唐詩/json/316.json','["偶尋烏府客，同醉習家池。積雪初迷徑，孤雲遂失期。", "風前勞引領，月下重相思。何必因尊酒，幽心兩自知。"]'),
('yuding-57','秋晚途次坊州界寄崔玉員外','武元衡','唐','御定全唐诗','yuding','','[]','崎嶇崖谷迷，寒雨暮成泥。征路出山頂，亂雲生馬蹄。',48,'御定全唐詩/json/316.json','["崎嶇崖谷迷，寒雨暮成泥。征路出山頂，亂雲生馬蹄。", "望鄉程杳杳，懷遠思淒淒。欲識分麾重，孤城萬壑西。"]'),
('yuding-58','度東徑嶺','武元衡','唐','御定全唐诗','yuding','','[]','又過雁門北，不勝南客悲。三邊上岩見，雙淚望鄉垂。',48,'御定全唐詩/json/316.json','["又過雁門北，不勝南客悲。三邊上岩見，雙淚望鄉垂。", "暮角雲中戍，殘陽天際旗。更看飛白羽，胡馬在封陲。"]'),
('yuding-59','送李正字之蜀','武元衡','唐','御定全唐诗','yuding','','[]','已獻甘泉賦，仍登片玉科。漢官新組綬，蜀國舊煙蘿。',48,'御定全唐詩/json/316.json','["已獻甘泉賦，仍登片玉科。漢官新組綬，蜀國舊煙蘿。", "劍壁秋雲斷，巴江夜月多。無窮別離思，遙寄竹枝歌。"]'),
('yuding-60','玉泉寺與潤上人望秋山懷張少尹','武元衡','唐','御定全唐诗','yuding','','[]','山寒天降霜，煙月共蒼蒼。況此綠岩晚，尚餘丹桂芳。',48,'御定全唐詩/json/316.json','["山寒天降霜，煙月共蒼蒼。況此綠岩晚，尚餘丹桂芳。", "禪心殊眾樂，人世滿秋光。莫怪頻回首，孤雲思帝鄉。"]'),
('yuding-61','酬崔使君寄麈尾','武元衡','唐','御定全唐诗','yuding','','[]','賢人嘉尚同，今制古遺風。寄我襟懷裏，辭君掌握中。',48,'御定全唐詩/json/316.json','["賢人嘉尚同，今制古遺風。寄我襟懷裏，辭君掌握中。", "金聲勞振遠，玉柄借談空。執玩馳心處，迢迢巴峽東。"]'),
('yuding-62','送鄧州潘使君赴任','武元衡','唐','御定全唐诗','yuding','','[]','川陸一都會，旌旗千里舒。虎符中禁授，熊軾上流居。',48,'御定全唐詩/json/316.json','["川陸一都會，旌旗千里舒。虎符中禁授，熊軾上流居。", "橘柚金難並，池塘練不如。春風行部日，應駐士元車。"]'),
('yuding-63','和李中丞題故將軍林亭','武元衡','唐','御定全唐诗','yuding','','[]','帝裏清和節，侯家邸第春。煙霏瑤草露，苔暗杏梁塵。',48,'御定全唐詩/json/316.json','["帝裏清和節，侯家邸第春。煙霏瑤草露，苔暗杏梁塵。", "城郭悲歌舊，池塘麗句新。年年車馬客，鐘鼓樂他人。"]'),
('yuding-64','送韋侍禦司議赴東都','武元衡','唐','御定全唐诗','yuding','','[]','洛京千里近，離緒亦紛紛。文憲芙蓉沼，元方羔雁群。',48,'御定全唐詩/json/316.json','["洛京千里近，離緒亦紛紛。文憲芙蓉沼，元方羔雁群。", "河關連鞏樹，嵩少接秦雲。獨有臨風思，睽攜不可聞。"]'),
('yuding-65','送吳侍禦司馬赴台州','武元衡','唐','御定全唐诗','yuding','','[]','盧耽佐郡遙，川陸共迢迢。風景輕吳會，文章變越謠。',48,'御定全唐詩/json/316.json','["盧耽佐郡遙，川陸共迢迢。風景輕吳會，文章變越謠。", "煙林繁橘柚，雲海浩波潮。餘有靈山夢，前君到石橋。"]'),
('yuding-66','送七兄赴歙州','武元衡','唐','御定全唐诗','yuding','','[]','車馬去憧憧，都門聞曉鐘。客程將日遠，離緒與春濃。',48,'御定全唐詩/json/316.json','["車馬去憧憧，都門聞曉鐘。客程將日遠，離緒與春濃。", "流水逾千度，歸雲隔萬重。玉杯傾酒盡，不換慘淒容。"]'),
('yuding-67','德宗皇帝挽歌詞三首','武元衡','唐','御定全唐诗','yuding','','[]','道啟軒皇聖，威揚夏禹功。謳歌亭育外，文武盛明中。',144,'御定全唐詩/json/316.json','["道啟軒皇聖，威揚夏禹功。謳歌亭育外，文武盛明中。", "日月光連璧，煙塵屏大風。為人祈福處，台樹與天通。", "聖曆□勤政，瑤圖慶運長。壽宮開此地，仙駕緲何鄉。", "風斷清笳調，雲愁綠旆揚。上升知不恨，弘濟任城王。", "嘗聞閶闔前，星拱北辰籙。今來大明祖，輦駕橋山曲。", "松柏韻幽音，魚龍焰寒燭。歲歲秋風辭，兆人歌不足。"]'),
('yuding-68','順宗至德大聖皇帝挽歌詞三首','武元衡','唐','御定全唐诗','yuding','','[]','橋山同軌會，軒後葬衣冠。東海風波變，西陵松柏攢。',144,'御定全唐詩/json/316.json','["橋山同軌會，軒後葬衣冠。東海風波變，西陵松柏攢。", "鼎湖仙已去，金掌露寧幹。萬木泉扃月，空憐鳧雁寒。", "容衛曉徘徊，嚴城閶闔開。烏號龍馭遠，遏密鳳聲哀。", "昆浪黃河注，崦嵫白日頹。恭聞天子孝，不忍望銅台。", "哀挽渭川曲，空歌汾水陽。夜泉愁更咽，秋日慘無光。", "纘夏功傳啟，興周業繼昌。回瞻五陵上，煙雨為蒼蒼。"]'),
('yuding-69','昭德皇后挽歌詞','武元衡','唐','御定全唐诗','yuding','','[]','玉扆將遷坐，金雞忽報晨。佩環仙馭遠，星月夜台新。',48,'御定全唐詩/json/316.json','["玉扆將遷坐，金雞忽報晨。佩環仙馭遠，星月夜台新。", "劍沒川空冷，菱寒鏡不春。國門車馬會，多是濯龍親。"]'),
('yuding-70','春晚奉陪相公西亭宴集','武元衡','唐','御定全唐诗','yuding','','[]','林花春向蘭，高會重邀歡。感物惜芳景，放懷因彩翰。',48,'御定全唐詩/json/316.json','["林花春向蘭，高會重邀歡。感物惜芳景，放懷因彩翰。", "玉顏穠處並，銀燭焰中看。若折持相贈，風光益別難。"]'),
('yuding-0','送崔判官使太原','武元衡','唐','御定全唐诗','yuding','','[]','勞君車馬此逡巡，我與劉君本世親。兩地山河分節制，',40,'御定全唐詩/json/317.json','["勞君車馬此逡巡，我與劉君本世親。兩地山河分節制，", "報主由來須盡敵，相期萬里寶刀新。"]'),
('yuding-1','幕中諸公有觀獵之作因繼之','武元衡','唐','御定全唐诗','yuding','','[]','刀州城北劍山東，甲士屯雲騎散風。旌旆遍張林嶺動，',40,'御定全唐詩/json/317.json','["刀州城北劍山東，甲士屯雲騎散風。旌旆遍張林嶺動，", "為報府中諸從事，燕然未勒莫論功。"]'),
('yuding-2','同幕中諸公送李侍禦歸朝','武元衡','唐','御定全唐诗','yuding','','[]','昔年專席奉清朝，今日持書即舊僚。珠履會中簫管思，',40,'御定全唐詩/json/317.json','["昔年專席奉清朝，今日持書即舊僚。珠履會中簫管思，", "歲月不堪相送盡，頹顏更被別離凋。"]'),
('yuding-3','送張六諫議歸朝','武元衡','唐','御定全唐诗','yuding','','[]','詔書前日下丹霄，頭戴儒冠脫皂貂。笛怨柳營煙漠漠，',40,'御定全唐詩/json/317.json','["詔書前日下丹霄，頭戴儒冠脫皂貂。笛怨柳營煙漠漠，", "歸去朝端如有問，玉關門外老班超。"]'),
('yuding-4','酬嚴司空荊南見寄','武元衡','唐','御定全唐诗','yuding','','[]','金貂再領三公府，玉帳連封萬戶侯。簾卷青山巫峽曉，',40,'御定全唐詩/json/317.json','["金貂再領三公府，玉帳連封萬戶侯。簾卷青山巫峽曉，", "白雪調高歌不得，美人南國翠蛾愁。"]'),
('yuding-5','南徐別業早春有懷','武元衡','唐','御定全唐诗','yuding','','[]','生涯擾擾竟何成，自愛深居隱姓名。遠雁臨空翻夕照，',40,'御定全唐詩/json/317.json','["生涯擾擾竟何成，自愛深居隱姓名。遠雁臨空翻夕照，", "虛度年華不相見，離腸懷土並關情。"]'),
('yuding-6','摩訶池宴','武元衡','唐','御定全唐诗','yuding','','[]','摩訶池上春光早，愛水看花日日來。穠李雪開歌扇掩，',40,'御定全唐詩/json/317.json','["摩訶池上春光早，愛水看花日日來。穠李雪開歌扇掩，", "晝短欲將清夜繼，西園自有月裴回。"]'),
('yuding-7','至櫟陽崇道寺聞嚴十少府趨侍','武元衡','唐','御定全唐诗','yuding','','[]','雲連萬木夕沉沉，草色泉聲古院深。聞說羊車趨盛府，',40,'御定全唐詩/json/317.json','["雲連萬木夕沉沉，草色泉聲古院深。聞說羊車趨盛府，", "惆悵送君身未達，不堪搖落聽秋砧。"]'),
('yuding-8','春暮郊居寄朱舍人','武元衡','唐','御定全唐诗','yuding','','[]','幽深不讓子真居，度日閑眠世事疏。春水滿池新雨霽，',40,'御定全唐詩/json/317.json','["幽深不讓子真居，度日閑眠世事疏。春水滿池新雨霽，", "回首知音青瑣闥，何時一為薦相如。"]'),
('yuding-9','送溫況游蜀','武元衡','唐','御定全唐诗','yuding','','[]','遊人西去客三巴，身逐孤蓬不定家。山近峨眉飛暮雨，',40,'御定全唐詩/json/317.json','["遊人西去客三巴，身逐孤蓬不定家。山近峨眉飛暮雨，", "應到嚴君開卦處，將餘一為問生涯。"]'),
('yuding-10','崔敷歎春物將謝恨不同覽時余方為事牽束及往尋不遇題之留贈','武元衡','唐','御定全唐诗','yuding','','[]','九陌遲遲麗景斜，禁街西訪隱淪賒。門依高柳空飛絮，',40,'御定全唐詩/json/317.json','["九陌遲遲麗景斜，禁街西訪隱淪賒。門依高柳空飛絮，", "殘陽寂寞東城去，惆悵春風落盡花。"]'),
('yuding-11','秋燈對雨寄史近崔積','武元衡','唐','御定全唐诗','yuding','','[]','坐聽宮城傳晚漏，起看衰葉下寒枝。空庭綠草結離念，',40,'御定全唐詩/json/317.json','["坐聽宮城傳晚漏，起看衰葉下寒枝。空庭綠草結離念，", "相逢莫厭尊前醉，春去秋來自不知。"]'),
('yuding-12','春題龍門香山寺','武元衡','唐','御定全唐诗','yuding','','[]','眾香天上梵仙宮，鐘磬寥寥半碧空。清景乍開松嶺月，',40,'御定全唐詩/json/317.json','["眾香天上梵仙宮，鐘磬寥寥半碧空。清景乍開松嶺月，", "欲盡出尋那可得，三千世界本無窮。"]'),
('yuding-13','酬陸三與鄒十八侍禦','武元衡','唐','御定全唐诗','yuding','','[]','城分流水郭連山，拂露開懷一解顏。令尹關中仙史會，',40,'御定全唐詩/json/317.json','["城分流水郭連山，拂露開懷一解顏。令尹關中仙史會，", "莫恨殷勤留此地，東崖桂樹昔同攀。"]'),
('yuding-14','酬談校書長安秋夜對月寄諸故舊','武元衡','唐','御定全唐诗','yuding','','[]','故園千里渺遐情，黃葉蕭條白露生。驚鵲繞枝風滿幌，',40,'御定全唐詩/json/317.json','["故園千里渺遐情，黃葉蕭條白露生。驚鵲繞枝風滿幌，", "莫怪孔融悲歲序，五侯門館重婁卿。"]'),
('yuding-15','送田三端公還鄂州','武元衡','唐','御定全唐诗','yuding','','[]','孤雲迢遞戀滄洲，勸酒梨花對白頭。南陌送歸車騎合，',40,'御定全唐詩/json/317.json','["孤雲迢遞戀滄洲，勸酒梨花對白頭。南陌送歸車騎合，", "君去庾公應借問，馳心千里大江流。"]'),
('yuding-16','送李秀才赴滑州詣大夫舅','武元衡','唐','御定全唐诗','yuding','','[]','陌頭車馬去翩翩，白麵懷書美少年。東武揚公姻婭重，',40,'御定全唐詩/json/317.json','["陌頭車馬去翩翩，白麵懷書美少年。東武揚公姻婭重，", "知己滿朝留不住，貴臣河上擁旌旃。"]'),
('yuding-17','秋日書懷','武元衡','唐','御定全唐诗','yuding','','[]','金貂玉鉉奉君恩，夜漏晨鐘老掖垣。參決萬機空有愧，',40,'御定全唐詩/json/317.json','["金貂玉鉉奉君恩，夜漏晨鐘老掖垣。參決萬機空有愧，", "倦鳥不知歸去日，青蕪白露滿郊園。"]'),
('yuding-18','南昌灘','武元衡','唐','御定全唐诗','yuding','','[]','渠江明淨峽逶迤，船到名灘拽𥮘遲。櫓窡動搖妨作夢，',40,'御定全唐詩/json/317.json','["渠江明淨峽逶迤，船到名灘拽𥮘遲。櫓窡動搖妨作夢，", "物色可憐心莫限，此行都是獨行時。"]'),
('yuding-19','奉和聖制豐年多慶九日示懷','武元衡','唐','御定全唐诗','yuding','','[]','令節寰宇泰，神都佳氣濃。賡歌禹功盛，擊壤堯年豐。',72,'御定全唐詩/json/317.json','["令節寰宇泰，神都佳氣濃。賡歌禹功盛，擊壤堯年豐。", "九奏碧霄裏，千官皇澤中。南山澄凝黛，曲水清涵空。", "金玉美王度，歡康謠國風。睿文垂日月，永與天無窮。"]'),
('yuding-20','夏日陪馮許二侍郎與嚴祕書遊昊天觀覽舊題寄同里楊華州中丞','武元衡','唐','御定全唐诗','yuding','','[]','三伏草木變，九城車馬煩。碧霄回騎射，丹洞入桃源。',72,'御定全唐詩/json/317.json','["三伏草木變，九城車馬煩。碧霄回騎射，丹洞入桃源。", "台殿雲浮棟，緌纓鶴在軒。莫將真破妄，聊用靜持喧。", "石甃古苔冷，水筠涼簟翻。黃公壚下歎，旌旆國東門。"]'),
('yuding-21','奉和聖制重陽日即事','武元衡','唐','御定全唐诗','yuding','','[]','玉燭降寒露，我皇歌古風。重陽德澤展，萬國歡娛同。',72,'御定全唐詩/json/317.json','["玉燭降寒露，我皇歌古風。重陽德澤展，萬國歡娛同。", "綺陌擁行騎，香塵凝曉空。神都自藹藹，佳氣助蔥蔥。", "律呂陰陽暢，景光天地通。徒然被鴻霈，無以報玄功。"]'),
('yuding-22','秋日台中寄懷簡諸僚','武元衡','唐','御定全唐诗','yuding','','[]','憲府日多事，秋光照碧林。幹雲岩翠合，布石地苔深。',96,'御定全唐詩/json/317.json','["憲府日多事，秋光照碧林。幹雲岩翠合，布石地苔深。", "憂悔耿遐抱，塵埃緇素襟。物情牽局促，友道曠招尋。", "頹節風霜變，流年芳景侵。池荷足幽氣，煙竹又繁陰。", "簪組赤墀戀，池魚滄海心。滌煩滯幽賞，永度瑤華音。"]'),
('yuding-23','奉酬淮南中書相公見寄','武元衡','唐','御定全唐诗','yuding','','[]','揚州隋故都，竹使漢名儒。翊聖恩華異，持衡節制殊。',144,'御定全唐詩/json/317.json','["揚州隋故都，竹使漢名儒。翊聖恩華異，持衡節制殊。", "朝廷連受脤，台座接籲謨。金玉裁王度，丹書奉帝俞。", "九重辭象魏，千里握兵符。鐵馬秋臨塞，虹旌夜渡瀘。", "江長梅笛怨，天遠桂輪孤。浩歎煙霜曉，芳期蘭蕙蕪。", "雅言書一劄，賓海雁東隅。歲月奔波盡，音徽霧雨濡。", "蜀江分井絡，錦浪入淮湖。獨抱相思恨，關山不可逾。"]'),
('yuding-24','甫構西亭偶題因呈監軍及幕中諸公','武元衡','唐','御定全唐诗','yuding','','[]','瀛海無因泛，昆丘豈易尋。數峰聊在目，一境暫清心。',120,'御定全唐詩/json/317.json','["瀛海無因泛，昆丘豈易尋。數峰聊在目，一境暫清心。", "悅彼松柏性，愛茲桃李陰。列芳憑有土，叢幹聚成林。", "信矣子牟戀，歸歟尼父吟。暗香蘭露滴，空翠蕙樓深。", "負鼎位嘗忝，荷戈年屢侵。百城煩鞅掌，九仞喜嶇嶔。", "巴漢溯沿楫，岷峨千萬岑。恩偏不敢去，範蠡畏熔金。"]'),
('yuding-25','和楊弘微春日曲江南望','武元衡','唐','御定全唐诗','yuding','','[]','遲景靄悠悠，傷春南陌頭。暄風一澹蕩，遐思幾殷優。',120,'御定全唐詩/json/317.json','["遲景靄悠悠，傷春南陌頭。暄風一澹蕩，遐思幾殷優。", "龍去空仙沼，鸞飛掩妓樓。芳菲餘雨露，冠蓋舊公侯。", "朱戟千門閉，黃鸝百囀愁。煙蒙宮樹晚，花咽石泉流。", "寒谷律潛應，中林蘭自幽。商山將避漢，晉室正藩周。", "黍稷聞興歎，瓊瑤畏見投。君心即吾事，微向在滄洲。"]'),
('yuding-26','長安秋夜懷陳京昆季','武元衡','唐','御定全唐诗','yuding','','[]','鐘鼓九衢絕，出門千里同。遠情高枕夜，秋思北窗空。',120,'御定全唐詩/json/317.json','["鐘鼓九衢絕，出門千里同。遠情高枕夜，秋思北窗空。", "靜見煙凝燭，閑聽葉墜桐。玉壺思洞徹，瓊樹憶蔥籠。", "螢影疏簾外，鴻聲暗雨中。羈愁難會面，懶慢責微躬。", "甲乙科攀桂，圖書閣踐蓬。一瓢非可樂，六翮未因風。", "寥落悲秋盡，蹉跎惜歲窮。明朝不相見，流淚菊花叢。"]'),
('yuding-27','冬日，漢江南行將赴夏口，途次江陵界，寄裴尚書','武元衡','唐','御定全唐诗','yuding','','[]','五部擁雙旌，南依墨客卿。關山迥梁甸，波浪接湓城。',120,'御定全唐詩/json/317.json','["五部擁雙旌，南依墨客卿。關山迥梁甸，波浪接湓城。", "煙景迷時候，雲帆渺去程。蛤珠馮月吐，蘆雁觸羅驚。", "浦樹凝寒晦，江天湛鏡清。賞心隨處愜，壯志逐年輕。", "舟楫不可駐，提封如任情。向方曾指路，射策許言兵。", "蘭渚歇芳意，菱歌非應聲。元戎武昌守，羊祜幸連營。"]'),
('yuding-28','奉酬中書李相公早朝于中書候傳點，偶書所懷','武元衡','唐','御定全唐诗','yuding','','[]','寥落曙鐘斷，微明煙月沉。翠霞仙仗合，清漏掖垣深。',120,'御定全唐詩/json/317.json','["寥落曙鐘斷，微明煙月沉。翠霞仙仗合，清漏掖垣深。", "北極星遙拱，南山闕迥臨。蘭釭竟曉焰，琪樹欲秋陰。", "霄漢慚聯步，貂蟬愧並簪。德容溫比玉，王度式如金。", "魚水千年運，簫韶九奏音。代天驚度日，擲地喜開襟。", "文武時方泰，唐虞道可尋。忝陪申及甫，清淨奉堯心。"]'),
('yuding-29','甲午歲相國李公有北園寄贈之作吟玩歷時屢促酬答機務不暇未及報章今古遽分電波增感留墓劍而心許感鄰笛而意傷寓哀冥寞以廣遺韻云','武元衡','唐','御定全唐诗','yuding','','[]','機事勞西掖，幽懷寄北園。鶴巢深更靜，蟬噪斷猶喧。',96,'御定全唐詩/json/317.json','["機事勞西掖，幽懷寄北園。鶴巢深更靜，蟬噪斷猶喧。", "仙醞百花馥，豔歌雙袖翻。碧雲詩變雅，皇澤葉流根。", "未報雕龍贈，俄傷淚劍痕。佳城關白日，哀挽向青門。", "禮命公台重，煙霜隴樹繁。天高不可問，空使輔星昏。"]'),
('yuding-30','和楊三舍人晚秋與崔二舍人張祕監苖考功同遊昊天觀時中書寓直不得陪隨因追往年曾與舊僚聯遊此觀紀題在壁已有淪亡書事感懷輒以呈寄兼呈東省三給事之作楊君見徵鄙詞因以繼和','武元衡','唐','御定全唐诗','yuding','','[]','瑤圃高秋會，金閨奉詔辰。朱輪天上客，白石洞中人。',96,'御定全唐詩/json/317.json','["瑤圃高秋會，金閨奉詔辰。朱輪天上客，白石洞中人。", "佩響泉聲雜，朝衣羽服親。九重青瑣閉，三秀紫芝新。", "化藥秦方士，偷桃漢侍臣。玉笙王子駕，遼鶴令威身。", "歎逝頹波速，緘詞麗曲春。重將淒恨意，苔壁問遺塵。"]'),
('yuding-31','酬李十一尚書西亭暇日書懷見寄十二韻之作','武元衡','唐','御定全唐诗','yuding','','[]','鼎鉉昔雲忝，西南分主憂。煙塵開僰道，旌節護蠻陬。',144,'御定全唐詩/json/317.json','["鼎鉉昔雲忝，西南分主憂。煙塵開僰道，旌節護蠻陬。", "任重功無立，力微恩未酬。據鞍慚齒發，責帥懼春秋。", "高德聞鄭履，儉居稱晏裘。三刀君入夢，九折我回輈。", "時景屢遷易，茲言期退休。方追故山事，豈謂臺階留。", "遐抱清淨理，眷言蘭杜幽。一緘瓊玖贈，萬里別離愁。", "巴嶺雲外沒，蜀江天際流。懷賢耿遙思，相望鳳池頭。"]'),
('yuding-32','秋懷奉寄朱補闕','武元衡','唐','御定全唐诗','yuding','','[]','上苑繁霜降，騷人起恨初。白雲深陋巷，衰草遍閒居。',72,'御定全唐詩/json/317.json','["上苑繁霜降，騷人起恨初。白雲深陋巷，衰草遍閒居。", "暮色秋煙重，寒聲牖葉虛。潘生秋思苦，陶令世情疏。", "已制歸田賦，猶陳諫獵書。不知青瑣客，投分竟何如。"]'),
('yuding-33','奉酬中書相公至日圜丘行事合於中書宿齋移止於集賢院敘情見寄之什','武元衡','唐','御定全唐诗','yuding','','[]','郊廟祗嚴祀，齋莊覿上玄。別開金虎觀，不離紫微天。',72,'御定全唐詩/json/317.json','["郊廟祗嚴祀，齋莊覿上玄。別開金虎觀，不離紫微天。", "樹古長楊接，池清太液連。仲山方補袞，文舉自傷年。", "風溢銅壺漏，香凝綺閣煙。仍聞白雪唱，流詠滿鶤弦。"]'),
('yuding-34','途次','武元衡','唐','御定全唐诗','yuding','','[]','去國策羸馬，勞歌行路難。地崇秦制險，人樂漢恩寬。',72,'御定全唐詩/json/317.json','["去國策羸馬，勞歌行路難。地崇秦制險，人樂漢恩寬。", "禦沼澄泉碧，宮梨佛露丹。鼎成仙馭遠，龍化宿雲殘。", "不問三苗寵，誰陪萬國歡。至今松桂色，長助玉樓寒。"]'),
('yuding-35','題故蔡國公主九華觀上池院','武元衡','唐','御定全唐诗','yuding','','[]','朱門臨九衢，雲木藹仙居。曲沼天波接，層台鳳舞餘。',72,'御定全唐詩/json/317.json','["朱門臨九衢，雲木藹仙居。曲沼天波接，層台鳳舞餘。", "曙煙深碧筱，香露濕紅蕖。瑤瑟含風韻，紗窗積翠虛。", "秦樓今寂寞，真界竟何如。不與蓬瀛異，迢迢遠玉除。"]'),
('yuding-36','酬嚴維秋夜見寄','武元衡','唐','御定全唐诗','yuding','','[]','遙夜思悠悠，聞鐘遠夢休。亂林螢燭暗，零露竹風秋。',96,'御定全唐詩/json/317.json','["遙夜思悠悠，聞鐘遠夢休。亂林螢燭暗，零露竹風秋。", "啟戶雲歸棟，褰簾月上鉤。昭明逢聖代，羈旅別滄洲。", "騎省潘郎思，衡闈宋玉愁。神仙慚李郭，詞賦謝曹劉。", "松柏應無變，瓊瑤不可酬。誰堪此時景，寂寞下高樓。"]'),
('yuding-37','途次近蜀驛蒙恩賜寶刀及飛龍廄馬使還奉寄中書李鄭二公','武元衡','唐','御定全唐诗','yuding','','[]','草草事行役，遲遲違故關。碧幃遙隱霧，紅旆漸依山。',72,'御定全唐詩/json/317.json','["草草事行役，遲遲違故關。碧幃遙隱霧，紅旆漸依山。", "感激酬恩淚，星霜去國顏。捧刀金錫字，歸馬玉連環。", "威鳳翔雙闕，征夫縱百蠻。應憐宣室召，溫樹不同攀。"]'),
('yuding-38','歸燕','武元衡','唐','御定全唐诗','yuding','','[]','春色遍芳菲，閑簷雙燕歸。還同舊侶至，來繞故巢飛。',72,'御定全唐詩/json/317.json','["春色遍芳菲，閑簷雙燕歸。還同舊侶至，來繞故巢飛。", "敢望煙霄達，多慚羽翮微。銜泥傍金砌，拾蕊到荊扉。", "雲海經時別，雕梁長日依。主人能一顧，轉盻自光輝。"]'),
('yuding-39','送許著作分司東都','武元衡','唐','御定全唐诗','yuding','','[]','瑤瑟激淒響，征鴻翻夕陽。署分刊竹簡，書蠹護芸香。',60,'御定全唐詩/json/317.json','["瑤瑟激淒響，征鴻翻夕陽。署分刊竹簡，書蠹護芸香。", "馬色關城曉，蟬聲驛路長。石渠榮正禮，蘭室重元方。", "不作經年別，離魂亦暫傷。"]'),
('yuding-40','聞相公三兄小園置宴以元衡寓直因寄上兼呈中書三兄','武元衡','唐','御定全唐诗','yuding','','[]','休沐限中禁，家山傳勝遊。露寒潘省夜，木落庾園秋。',72,'御定全唐詩/json/317.json','["休沐限中禁，家山傳勝遊。露寒潘省夜，木落庾園秋。", "蘭菊回幽步，壺觴洽舊儔。位高天祿閣，詞異畔牢愁。", "孤思琴先覺，馳暉水競流。明朝不相見，清祀在圜丘。"]'),
('yuding-41','酬陸員外歙州許員外郢州二使君','武元衡','唐','御定全唐诗','yuding','','[]','吳洲雲海接，楚驛夢林長。符節分憂重，鵷鴻去路翔。',72,'御定全唐詩/json/317.json','["吳洲雲海接，楚驛夢林長。符節分憂重，鵷鴻去路翔。", "豔歌愁翠黛，寶瑟韻清商。洲草遙池合，春風曉旆張。", "晉臣多樂廣，漢主識馮唐。不作經年別，離魂亦未傷。"]'),
('yuding-42','漸至涪州先寄王使君','武元衡','唐','御定全唐诗','yuding','','[]','治教通夷俗，均輸問大田。江分巴字水，樹入夜郎煙。',72,'御定全唐詩/json/317.json','["治教通夷俗，均輸問大田。江分巴字水，樹入夜郎煙。", "毒霧含秋氣，陰岩蔽曙天。路難空計日，身老不由年。", "將命寧知遠，歸心詎可傳。星郎複何事，出守五溪邊。"]'),
('yuding-43','石州城','武元衡','唐','御定全唐诗','yuding','','[]','丈夫心愛橫行，報國知嫌命輕。樓蘭徑百戰，',20,'御定全唐詩/json/317.json','["丈夫心愛橫行，報國知嫌命輕。樓蘭徑百戰，"]'),
('yuding-44','寒食下第','武元衡','唐','御定全唐诗','yuding','','[]','柳掛九衢絲，花飄萬家雪。如何憔悴人，對此芳菲節。',24,'御定全唐詩/json/317.json','["柳掛九衢絲，花飄萬家雪。如何憔悴人，對此芳菲節。"]'),
('yuding-45','途中即事','武元衡','唐','御定全唐诗','yuding','','[]','南征複北還，擾擾百年間。自笑紅塵裏，生涯不暫閑。',24,'御定全唐詩/json/317.json','["南征複北還，擾擾百年間。自笑紅塵裏，生涯不暫閑。"]'),
('yuding-46','春日偶作','武元衡','唐','御定全唐诗','yuding','','[]','縱橫桃李枝，淡蕩春風吹。美人歌白苧，萬恨在蛾眉。',24,'御定全唐詩/json/317.json','["縱橫桃李枝，淡蕩春風吹。美人歌白苧，萬恨在蛾眉。"]'),
('yuding-47','夏夜作','武元衡','唐','御定全唐诗','yuding','','[]','夜久喧暫息，池台惟月明。無因駐清景，日出事還生。',24,'御定全唐詩/json/317.json','["夜久喧暫息，池台惟月明。無因駐清景，日出事還生。"]'),
('yuding-48','左掖梨花','武元衡','唐','御定全唐诗','yuding','','[]','巧笑解迎人，晴雪香堪惜。隨風蝶影翻，誤點朝衣赤。',24,'御定全唐詩/json/317.json','["巧笑解迎人，晴雪香堪惜。隨風蝶影翻，誤點朝衣赤。"]'),
('yuding-49','同陳六侍禦寒食游禪定藏山上人院','武元衡','唐','御定全唐诗','yuding','','[]','年少輕行樂，東城南陌頭。與君寂寞意，共作草堂遊。',24,'御定全唐詩/json/317.json','["年少輕行樂，東城南陌頭。與君寂寞意，共作草堂遊。"]'),
('yuding-50','贈佳人','武元衡','唐','御定全唐诗','yuding','','[]','步搖金翠玉搔頭，傾國傾城勝莫愁。',32,'御定全唐詩/json/317.json','["步搖金翠玉搔頭，傾國傾城勝莫愁。", "若逞仙姿遊洛浦，定知神女謝風流。"]'),
('yuding-51','休暇日，中書相公致齋禁省，因以寄贈','武元衡','唐','御定全唐诗','yuding','','[]','嘗聞聖主得賢臣，三接能令四海春。',32,'御定全唐詩/json/317.json','["嘗聞聖主得賢臣，三接能令四海春。", "月滿禁垣齋沐夜，清吟屬和更何人。"]'),
('yuding-52','春興','武元衡','唐','御定全唐诗','yuding','','[]','楊柳陰陰細雨晴，殘花落盡見流鶯。',32,'御定全唐詩/json/317.json','["楊柳陰陰細雨晴，殘花落盡見流鶯。", "春風一夜吹香夢，夢逐春風到洛城。"]'),
('yuding-53','酬裴起居西亭留題','武元衡','唐','御定全唐诗','yuding','','[]','豔歌能起關山恨，紅燭偏凝寒塞情。',32,'御定全唐詩/json/317.json','["豔歌能起關山恨，紅燭偏凝寒塞情。", "況是池塘風雨夜，不堪絲管盡離聲。"]'),
('yuding-54','送張侍禦赴京','武元衡','唐','御定全唐诗','yuding','','[]','江南煙雨塞鴻飛，西府文章謝掾歸。',32,'御定全唐詩/json/317.json','["江南煙雨塞鴻飛，西府文章謝掾歸。", "相送汀州蘭棹晚，菱歌一曲淚沾衣。"]'),
('yuding-55','鄂渚送友','武元衡','唐','御定全唐诗','yuding','','[]','雲帆淼淼巴陵渡，煙樹蒼蒼故郢城。',32,'御定全唐詩/json/317.json','["雲帆淼淼巴陵渡，煙樹蒼蒼故郢城。", "江上梅花無數落，送君南浦不勝情。"]'),
('yuding-56','送裴戡行軍','武元衡','唐','御定全唐诗','yuding','','[]','珠履三千醉不歡，玉人猶苦夜冰寒。',32,'御定全唐詩/json/317.json','["珠履三千醉不歡，玉人猶苦夜冰寒。", "送君偏有無言淚，天下關山行路難。"]'),
('yuding-57','宿青陽驛','武元衡','唐','御定全唐诗','yuding','','[]','空山搖落三秋暮，螢過疏簾月露團。',32,'御定全唐詩/json/317.json','["空山搖落三秋暮，螢過疏簾月露團。", "寂寞銀燈愁不寐，蕭蕭風竹夜窗寒。"]'),
('yuding-58','送崔舍人起居','武元衡','唐','御定全唐诗','yuding','','[]','赤墀同拜紫泥封，駟牡連征侍九重。',32,'御定全唐詩/json/317.json','["赤墀同拜紫泥封，駟牡連征侍九重。", "惟有白須張司馬，不言名利尚相從。"]'),
('yuding-59','路岐重賦','武元衡','唐','御定全唐诗','yuding','','[]','芳郊欲別闌幹淚，故國難期聚散雲。',32,'御定全唐詩/json/317.json','["芳郊欲別闌幹淚，故國難期聚散雲。", "分手更逢江驛暮，馬嘶猿叫不堪聞。"]'),
('yuding-60','重送盧三十一起居','武元衡','唐','御定全唐诗','yuding','','[]','相如擁傳有光輝，何事闌幹淚濕衣。',32,'御定全唐詩/json/317.json','["相如擁傳有光輝，何事闌幹淚濕衣。", "舊府東山餘妓在，重將歌舞送君歸。"]'),
('yuding-61','送張諫議','武元衡','唐','御定全唐诗','yuding','','[]','漢庭從事五人來，回首疆場獨未回。',32,'御定全唐詩/json/317.json','["漢庭從事五人來，回首疆場獨未回。", "今日送君魂斷處，寒雲寥落數株梅。"]'),
('yuding-62','同諸公夜宴監軍玩花之作','武元衡','唐','御定全唐诗','yuding','','[]','五侯門館百花繁，紅燭搖風白雪翻。',32,'御定全唐詩/json/317.json','["五侯門館百花繁，紅燭搖風白雪翻。", "不似鳳凰池畔見，飄揚今隔上林園。"]'),
('yuding-63','郊居寓目偶題','武元衡','唐','御定全唐诗','yuding','','[]','晨趨禁掖暮郊園，松桂蒼蒼煙露繁。',32,'御定全唐詩/json/317.json','["晨趨禁掖暮郊園，松桂蒼蒼煙露繁。", "明月上時群動息，雪峰高處正當軒。"]'),
('yuding-64','題嘉陵驛','武元衡','唐','御定全唐诗','yuding','','[]','悠悠風旆繞山川，山驛空蒙雨似煙。',32,'御定全唐詩/json/317.json','["悠悠風旆繞山川，山驛空蒙雨似煙。", "路半嘉陵頭已白，蜀門西上更青天。"]'),
('yuding-65','送柳郎中裴起居','武元衡','唐','御定全唐诗','yuding','','[]','望鄉臺上秦人在，學射山中杜魄哀。',32,'御定全唐詩/json/317.json','["望鄉臺上秦人在，學射山中杜魄哀。", "落日河橋千騎別，春風寂寞旆旌回。"]'),
('yuding-66','秋日出遊偶作','武元衡','唐','御定全唐诗','yuding','','[]','黃花丹葉滿江城，暫愛江頭風景清。',32,'御定全唐詩/json/317.json','["黃花丹葉滿江城，暫愛江頭風景清。", "閒步欲舒山野性，貔貅不許獨行人。"]'),
('yuding-67','夏夜餞裴行軍赴朝命','武元衡','唐','御定全唐诗','yuding','','[]','三年同看錦城花，銀燭連宵照綺霞。',32,'御定全唐詩/json/317.json','["三年同看錦城花，銀燭連宵照綺霞。", "報國從來先意氣，臨岐不用重咨嗟。"]'),
('yuding-68','摩訶池送李侍禦之鳳翔','武元衡','唐','御定全唐诗','yuding','','[]','柳暗花明池上山，高樓歌酒換離顏。',32,'御定全唐詩/json/317.json','["柳暗花明池上山，高樓歌酒換離顏。", "他時欲寄相思字，何處黃雲是隴間。"]'),
('yuding-69','送魏正則擢第歸江陵','武元衡','唐','御定全唐诗','yuding','','[]','商山路接玉山深，古木蒼然盡合陰。',32,'御定全唐詩/json/317.json','["商山路接玉山深，古木蒼然盡合陰。", "會府登筵君最少，江城秋至肯驚心。"]'),
('yuding-70','登闔閭古城','武元衡','唐','御定全唐诗','yuding','','[]','登高望遠自傷情，柳發花開映古城。',32,'御定全唐詩/json/317.json','["登高望遠自傷情，柳發花開映古城。", "全盛已隨流水去，黃鸝空囀舊春聲。"]'),
('yuding-71','尋三藏上人','武元衡','唐','御定全唐诗','yuding','','[]','北風吹雪暮蕭蕭，問法尋僧上界遙。',32,'御定全唐詩/json/317.json','["北風吹雪暮蕭蕭，問法尋僧上界遙。", "臨水手持筇竹杖，逢君不語指芭蕉。"]'),
('yuding-72','山居','武元衡','唐','御定全唐诗','yuding','','[]','身依泉壑將時背，路入煙蘿得地深。',32,'御定全唐詩/json/317.json','["身依泉壑將時背，路入煙蘿得地深。", "終歲不知城郭事，手栽林竹盡成陰。"]'),
('yuding-73','長安賊中寄題江南所居茱萸樹','武元衡','唐','御定全唐诗','yuding','','[]','手種茱萸舊井傍，幾回春露又秋霜。',32,'御定全唐詩/json/317.json','["手種茱萸舊井傍，幾回春露又秋霜。", "今來獨向秦中見，攀折無時不斷腸。"]'),
